import React, { useState, useEffect } from 'react';
import { Star, MessageCircle } from 'lucide-react';
import AvaliacaoModal from './AvaliacaoModal';
import ListaAvaliacoes from './ListaAvaliacoes';

export default function AbaPadronizadaAvaliacoes({
    usuarioId,
    tipoUsuario, // 'cliente', 'barbeiro', 'barbearia'
    nomeUsuario,
    API_URL,
    token,
    notify
}) {
    const [avaliacoes, setAvaliacoes] = useState([]);
    const [carregando, setCarregando] = useState(true);
    const [modalAberta, setModalAberta] = useState(false);
    const [chamadoSelecionado, setChamadoSelecionado] = useState(null);
    const [chamadosPendentes, setChamadosPendentes] = useState([]);

    // Carregar avalia├º├Áes do usu├írio
    useEffect(() => {
        carregarAvaliacoes();
        carregarChamadosPendentes();
    }, [usuarioId, tipoUsuario]);

    const carregarAvaliacoes = async () => {
        setCarregando(true);
        try {
            const endpoint = `/api/v1/avaliacoes/usuario/${usuarioId}`;

            const res = await fetch(`${API_URL}${endpoint}`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });

            if (res.ok) {
                const data = await res.json();
                const lista = Array.isArray(data) ? data : data.avaliacoes || [];
                setAvaliacoes(lista);
            }
        } catch (err) {
            if (notify) {
                notify('Erro ao carregar avaliacoes', 'error');
            }
        } finally {
            setCarregando(false);
        }
    };

    const handleEnviarAvaliacao = async (dados) => {
        try {
            const alvoId = tipoUsuario === 'cliente'
                ? (chamadoSelecionado?.barbeiro_id || chamadoSelecionado?.barbearia_usuario_id)
                : chamadoSelecionado?.cliente_id;

            if (!alvoId) {
                notify('Nao foi possivel identificar quem deve ser avaliado', 'error');
                return false;
            }

            const payload = {
                chamado_id: chamadoSelecionado.id,
                avaliado_id: alvoId,
                nota: dados.nota,
                comentario: dados.comentario
            };

            const res = await fetch(`${API_URL}/api/v1/avaliacoes/criar`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify(payload)
            });

            if (res.ok) {
                notify('Avalia├º├úo enviada com sucesso! Ô£à', 'success');
                carregarAvaliacoes();
                
                // Recarregar chamados pendentes para pr├│ximo
                const proximos = await carregarChamadosPendentes();
                // Se h├í pr├│ximo chamado pendente, seleciona automaticamente
                if (proximos && proximos.length > 0) {
                    setChamadoSelecionado(proximos[0]);
                }
                // Retorna true para n├úo fechar a modal - usu├írio fecha com X
                return true;
            } else {
                notify('Erro ao enviar avalia├º├úo', 'error');
                return false;
            }
        } catch (err) {
            notify('Erro ao enviar avalia├º├úo', 'error');
            return false;
        }
    };

    const carregarChamadosPendentes = async () => {
        try {
            // Buscar chamados conclu├¡dos que ainda n├úo foram avaliados
            let endpoint = tipoUsuario === 'cliente'
                ? '/api/v1/cliente/meus_pedidos'
                : tipoUsuario === 'barbeiro'
                ? '/api/v1/barbeiro/agendamentos/meus'
                : null;

            if (tipoUsuario === 'barbearia') {
                const barbeariaRes = await fetch(`${API_URL}/api/v1/barbearia/minha`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });

                if (!barbeariaRes.ok) {
                    return null;
                }

                const barbearia = await barbeariaRes.json();
                endpoint = `/api/v1/barbearia/${barbearia.id}/agendamentos`;
            }

            if (!endpoint) {
                return null;
            }

            const res = await fetch(`${API_URL}${endpoint}`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });

            if (res.ok) {
                const data = await res.json();
                const pendentes = (Array.isArray(data) ? data : data.chamados || [])
                    .filter(ch => {
                        const status = String(ch.status || '').toLowerCase();
                        return (status === 'concluido' || status === 'conclu├¡do') && !ch.avaliado;
                    })
                    .slice(0, 3);
                setChamadosPendentes(pendentes);
                return pendentes;
            }
        } catch (err) {
            if (notify) {
                notify('Erro ao carregar chamados', 'error');
            }
            return null;
        }
    };

    const handleAvaliarClick = (chamado) => {
        setChamadoSelecionado(chamado);
        setModalAberta(true);
    };

    return (
        <div className="space-y-6 pb-24">
            {/* Cabe├ºalho */}
            <div className="flex items-center gap-3">
                <div className="bg-orange-600/20 p-3 rounded-full">
                    <Star size={24} className="text-orange-500" />
                </div>
                <div>
                    <h2 className="text-2xl font-bold text-white">Avalia├º├Áes</h2>
                    <p className="text-zinc-400 text-sm">
                        {tipoUsuario === 'cliente'
                            ? 'Avalia├º├Áes que voc├¬ deu'
                            : 'Avalia├º├Áes que voc├¬ recebeu'}
                    </p>
                </div>
            </div>

            {/* Avalia├º├Áes Pendentes */}
            {chamadosPendentes.length > 0 && (
                <div className="bg-blue-900/20 border border-blue-500 rounded-2xl p-6">
                    <h3 className="text-lg font-bold text-blue-300 mb-4 flex items-center gap-2">
                        <MessageCircle size={20} />
                        Voc├¬ tem {chamadosPendentes.length} avalia├º├úo{chamadosPendentes.length > 1 ? '├Áes' : ''} pendente{chamadosPendentes.length > 1 ? 's' : ''}
                    </h3>

                    <div className="space-y-3">
                        {chamadosPendentes.map((chamado) => (
                            <div
                                key={chamado.id}
                                className="bg-zinc-900 border border-zinc-800 rounded-lg p-4 flex justify-between items-center"
                            >
                                <div>
                                    <p className="font-bold text-white text-sm">
                                        {tipoUsuario === 'cliente'
                                            ? `${chamado.barbeiro_nome || 'Barbeiro'} - ${chamado.servico_nome || 'Servi├ºo'}`
                                            : `${chamado.cliente_nome || 'Cliente'} - ${chamado.servico_nome || 'Servi├ºo'}`}
                                    </p>
                                    <p className="text-zinc-500 text-xs">
                                        {chamado.concluido_em || chamado.data_hora_inicio
                                            ? new Date(chamado.concluido_em || chamado.data_hora_inicio).toLocaleDateString('pt-BR')
                                            : 'Data nao informada'}
                                    </p>
                                </div>
                                <button
                                    onClick={() => handleAvaliarClick(chamado)}
                                    className="bg-orange-600 hover:bg-orange-700 text-white px-4 py-2 rounded-lg font-bold text-sm flex items-center gap-2 transition-colors"
                                >
                                    <Star size={16} />
                                    Avaliar
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Lista de Avalia├º├Áes */}
            {carregando ? (
                <div className="text-center py-12">
                    <div className="inline-block">
                        <div className="w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin" />
                    </div>
                    <p className="text-zinc-500 mt-3">Carregando avalia├º├Áes...</p>
                </div>
            ) : (
                <ListaAvaliacoes avaliacoes={avaliacoes} />
            )}

            {/* Modal */}
            <AvaliacaoModal
                isOpen={modalAberta}
                onClose={() => {
                    setModalAberta(false);
                    setChamadoSelecionado(null);
                }}
                onSubmit={handleEnviarAvaliacao}
                titulo={tipoUsuario === 'cliente'
                    ? `Avaliar ${chamadoSelecionado?.barbeiro_nome || 'Barbeiro'}`
                    : `Avaliar ${chamadoSelecionado?.cliente_nome || 'Cliente'}`}
            />
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { CreditCard, Check, AlertCircle, TrendingDown } from 'lucide-react';

const API_URL = import.meta.env.VITE_API_URL || "http://localhost:8000";

export default function AssinaturaPage({ token, notify }) {
    const [qtdCadeiras, setQtdCadeiras] = useState(1);
    const [assinaturaAtual, setAssinaturaAtual] = useState(null);
    const [loading, setLoading] = useState(false);
    const [pagamentoProcessando, setPagamentoProcessando] = useState(false);
    const [metodoPagamento, setMetodoPagamento] = useState('pix');

    // Regra de neg├│cio: valor acumulado progressivo por cadeira
    const obterPrecoCadeiraPorPosicao = (posicao) => {
        if (posicao === 1) return 47.90;
        if (posicao === 2) return 37.90;
        if (posicao === 3) return 27.90;
        if (posicao === 4) return 20.90;
        return 17.90;
    };

    const breakdown = Array.from({ length: qtdCadeiras }, (_, idx) => ({
        cadeira: idx + 1,
        valor: obterPrecoCadeiraPorPosicao(idx + 1),
    }));

    const totalMensal = breakdown.reduce((acc, item) => acc + item.valor, 0);
    const precoCadeiraAtual = obterPrecoCadeiraPorPosicao(qtdCadeiras);

    // Calcular economia vs plano individual
    const economiaVsIndividual = ((47.90 * qtdCadeiras) - totalMensal).toFixed(2);

    // Carregar assinatura atual
    useEffect(() => {
        carregarAssinatura();
    }, []);

    const carregarAssinatura = async () => {
        setLoading(true);
        try {
            const res = await fetch(`${API_URL}/api/v1/assinaturas/minha-assinatura`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });

            if (res.ok) {
                const data = await res.json();
                setAssinaturaAtual(data);
                if (data.cadeiras_ativas) {
                    setQtdCadeiras(data.cadeiras_ativas);
                }
            } else if (res.status !== 404) {
                notify('Erro ao carregar assinatura', 'error');
            }
        } catch (err) {
            console.error('Erro ao carregar assinatura:', err);
        } finally {
            setLoading(false);
        }
    };

    const processarPagamento = async () => {
        setPagamentoProcessando(true);
        try {
            const res = await fetch(`${API_URL}/api/v1/assinaturas/criar`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    cadeiras_ativas: qtdCadeiras,
                    metodo_pagamento: metodoPagamento
                })
            });

            const data = await res.json();

            if (res.ok) {
                const metodoLabel = metodoPagamento === 'pix'
                    ? 'PIX'
                    : metodoPagamento === 'cartao'
                        ? 'Cartao de Credito'
                        : 'Cartao';
                notify(`Assinatura de ${qtdCadeiras} cadeira(s) ativada com sucesso via ${metodoLabel}!`, 'success');
                await carregarAssinatura();
            } else {
                notify(data.detail || 'Erro ao processar pagamento', 'error');
            }
        } catch (err) {
            notify('Erro ao conectar com servidor', 'error');
            console.error('Erro:', err);
        } finally {
            setPagamentoProcessando(false);
        }
    };

    const renovarAssinatura = async () => {
        setPagamentoProcessando(true);
        try {
            const res = await fetch(`${API_URL}/api/v1/assinaturas/renovar`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    metodo_pagamento: metodoPagamento
                })
            });

            const data = await res.json();

            if (res.ok) {
                notify('Assinatura renovada com sucesso!', 'success');
                await carregarAssinatura();
            } else {
                notify(data.detail || 'Erro ao renovar assinatura', 'error');
            }
        } catch (err) {
            notify('Erro ao conectar com servidor', 'error');
        } finally {
            setPagamentoProcessando(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center h-screen bg-black">
                <div className="text-white text-center">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-orange-500 mx-auto mb-4"></div>
                    <p>Carregando...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-black text-white p-4 pb-24">
            <div className="max-w-2xl mx-auto">
                {/* Header */}
                <div className="mb-6">
                    <h1 className="text-2xl font-bold mb-2">Assinatura BarberMove</h1>
                    <p className="text-zinc-400 text-sm">Gerenciamento de Cadeiras para sua Barbearia</p>
                </div>

                {/* Status da Assinatura Atual */}
                {assinaturaAtual && (
                    <div className="bg-gradient-to-br from-green-900/30 to-green-800/20 border border-green-700/50 rounded-xl p-4 mb-6">
                        <div className="flex items-start gap-3">
                            <Check className="text-green-400 mt-1" size={20} />
                            <div className="flex-1">
                                <h3 className="font-bold text-green-400 mb-1">Assinatura Ativa</h3>
                                <p className="text-sm text-zinc-300">
                                    <span className="font-bold">{assinaturaAtual.cadeiras_ativas}</span> cadeira(s) ativa(s)
                                </p>
                                <p className="text-xs text-zinc-400 mt-1">
                                    Vence em: {new Date(assinaturaAtual.proximo_vencimento).toLocaleDateString('pt-BR')}
                                </p>
                                <p className="text-xs text-zinc-400">
                                    Valor: R$ {assinaturaAtual.valor_mensal?.toFixed(2)}
                                </p>
                                <p className="text-xs text-zinc-400">
                                    Metodo: {(assinaturaAtual.metodo_pagamento || 'pix').replace('_', ' ')}
                                </p>
                            </div>
                        </div>
                        <button
                            onClick={renovarAssinatura}
                            disabled={pagamentoProcessando}
                            className="w-full mt-3 bg-green-600 hover:bg-green-700 text-white py-2 px-4 rounded-lg font-bold text-sm transition disabled:opacity-50"
                        >
                            {pagamentoProcessando ? 'Processando...' : 'Renovar Assinatura'}
                        </button>
                    </div>
                )}

                {/* Seletor de Cadeiras */}
                <div className="bg-zinc-900 border border-zinc-800 rounded-xl p-6 mb-6">
                    <label className="block text-sm font-bold mb-4 text-zinc-300">
                        Quantas cadeiras quer ativar?
                    </label>
                    
                    <div className="flex items-center justify-center gap-6 mb-6">
                        <button
                            onClick={() => setQtdCadeiras(Math.max(1, qtdCadeiras - 1))}
                            className="w-12 h-12 bg-zinc-800 hover:bg-zinc-700 rounded-full text-2xl font-bold transition active:scale-95"
                        >
                            -
                        </button>
                        
                        <div className="text-center">
                            <div className="text-5xl font-bold text-orange-500">{qtdCadeiras}</div>
                            <div className="text-xs text-zinc-500 mt-1">
                                {qtdCadeiras === 1 ? 'cadeira' : 'cadeiras'}
                            </div>
                        </div>
                        
                        <button
                            onClick={() => setQtdCadeiras(qtdCadeiras + 1)}
                            className="w-12 h-12 bg-zinc-800 hover:bg-zinc-700 rounded-full text-2xl font-bold transition active:scale-95"
                        >
                            +
                        </button>
                    </div>

                    {/* Indicador de Desconto */}
                    {qtdCadeiras >= 2 && (
                        <div className="bg-gradient-to-r from-orange-900/30 to-red-900/30 border border-orange-700/50 rounded-lg p-3 mb-4">
                            <div className="flex items-center gap-2">
                                <TrendingDown className="text-orange-400" size={18} />
                                <div className="flex-1">
                                    <p className="text-xs font-bold text-orange-400">
                                        {qtdCadeiras === 2 ? 'Pre├ºo progressivo aplicado!' : 'Desconto progressivo aplicado!'}
                                    </p>
                                    <p className="text-xs text-zinc-400">
                                        Voc├¬ economiza R$ {economiaVsIndividual}/m├¬s
                                    </p>
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                {/* Resumo de Valores */}
                <div className="bg-zinc-900 border border-zinc-800 rounded-xl p-6 mb-6">
                    <label className="block text-sm font-bold mb-3 text-zinc-300">
                        Forma de pagamento
                    </label>
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-2 mb-6">
                        <button
                            type="button"
                            onClick={() => setMetodoPagamento('pix')}
                            className={`rounded-lg px-3 py-2 text-sm font-bold border transition ${metodoPagamento === 'pix' ? 'bg-orange-600/20 border-orange-500 text-orange-300' : 'bg-zinc-800 border-zinc-700 text-zinc-300 hover:bg-zinc-700'}`}
                        >
                            PIX
                        </button>
                        <button
                            type="button"
                            onClick={() => setMetodoPagamento('cartao')}
                            className={`rounded-lg px-3 py-2 text-sm font-bold border transition ${metodoPagamento === 'cartao' ? 'bg-orange-600/20 border-orange-500 text-orange-300' : 'bg-zinc-800 border-zinc-700 text-zinc-300 hover:bg-zinc-700'}`}
                        >
                            Cartao
                        </button>
                    </div>

                    <div className="space-y-3">
                        <div className="flex justify-between items-center pb-3 border-b border-zinc-800">
                            <span className="text-zinc-400 text-sm">Valor da {qtdCadeiras}a cadeira:</span>
                            <span className="text-green-400 font-bold text-lg">
                                R$ {precoCadeiraAtual.toFixed(2)}
                            </span>
                        </div>
                        
                        <div className="space-y-1 pb-3 border-b border-zinc-800">
                            <span className="text-zinc-400 text-sm">Detalhamento:</span>
                            {breakdown.map((item) => (
                                <div key={item.cadeira} className="flex justify-between items-center text-xs">
                                    <span className="text-zinc-500">{item.cadeira}a cadeira</span>
                                    <span className="text-zinc-300">R$ {item.valor.toFixed(2)}</span>
                                </div>
                            ))}
                        </div>

                        <div className="flex justify-between items-center pt-2">
                            <span className="text-lg font-bold">Total Mensal:</span>
                            <span className="text-2xl font-bold text-orange-500">
                                R$ {totalMensal.toFixed(2)}
                            </span>
                        </div>
                    </div>

                    {/* Bot├úo de Pagamento */}
                    <button
                        onClick={processarPagamento}
                        disabled={pagamentoProcessando}
                        className="w-full mt-6 bg-gradient-to-r from-orange-600 to-red-600 hover:from-orange-700 hover:to-red-700 text-white py-4 px-6 rounded-xl font-bold text-lg transition active:scale-95 disabled:opacity-50 flex items-center justify-center gap-2"
                    >
                        {pagamentoProcessando ? (
                            <>
                                <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
                                Processando...
                            </>
                        ) : (
                            <>
                                <CreditCard size={20} />
                                {assinaturaAtual ? 'Alterar Plano' : 'Ativar Assinatura'}
                            </>
                        )}
                    </button>
                </div>

                {/* Informa├º├Áes Adicionais */}
                <div className="bg-blue-900/20 border border-blue-700/30 rounded-xl p-4">
                    <div className="flex items-start gap-3">
                        <AlertCircle className="text-blue-400 mt-0.5" size={18} />
                        <div className="text-xs text-blue-300">
                            <p className="font-bold mb-1">Como funciona:</p>
                            <ul className="space-y-1 text-blue-200/80">
                                <li>ÔÇó Desconto autom├ítico conforme voc├¬ adiciona cadeiras</li>
                                <li>ÔÇó Cobran├ºa mensal recorrente</li>
                                <li>ÔÇó Barbeiros ganham acesso ├ás cadeiras contratadas</li>
                                <li>ÔÇó Cancele ou ajuste a quantidade a qualquer momento</li>
                            </ul>
                        </div>
                    </div>
                </div>

                {/* Tabela de Pre├ºos */}
                <div className="mt-6 bg-zinc-900 border border-zinc-800 rounded-xl p-4">
                    <h3 className="font-bold text-sm mb-3 text-zinc-300">Tabela de Pre├ºos</h3>
                    <div className="space-y-2 text-xs">
                        <div className="flex justify-between items-center py-2 border-b border-zinc-800">
                            <span className="text-zinc-400">1a cadeira</span>
                            <span className="font-bold">R$ 47,90</span>
                        </div>
                        <div className="flex justify-between items-center py-2 border-b border-zinc-800">
                            <span className="text-zinc-400">2a cadeira</span>
                            <span className="font-bold text-green-400">R$ 37,90</span>
                        </div>
                        <div className="flex justify-between items-center py-2 border-b border-zinc-800">
                            <span className="text-zinc-400">3a cadeira</span>
                            <span className="font-bold text-green-400">R$ 27,90</span>
                        </div>
                        <div className="flex justify-between items-center py-2 border-b border-zinc-800">
                            <span className="text-zinc-400">4a cadeira</span>
                            <span className="font-bold text-green-400">R$ 20,90</span>
                        </div>
                        <div className="flex justify-between items-center py-2">
                            <span className="text-zinc-400">6a em diante</span>
                            <span className="font-bold text-green-400">R$ 17,90</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { AlertTriangle, X, CreditCard } from 'lucide-react';

/**
 * Banner de alerta que aparece no topo do dashboard da barbearia
 * para avisar sobre vencimento pr├│ximo ou bloqueio
 */
export default function BannerVencimentoAssinatura({ token, onNavigateToPagamento }) {
  const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:8000';
  
  const [status, setStatus] = useState(null);
  const [dismissed, setDismissed] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    verificarStatus();
    // Verifica a cada 5 minutos
    const interval = setInterval(verificarStatus, 5 * 60 * 1000);
    return () => clearInterval(interval);
  }, []);

  const verificarStatus = async () => {
    try {
      const res = await fetch(`${API_URL}/api/v1/assinaturas/status`, {
        headers: { Authorization: `Bearer ${token}` }
      });

      if (res.ok) {
        const data = await res.json();
        setStatus(data);
      }
    } catch (err) {
      console.error('Erro ao verificar status:', err);
    } finally {
      setLoading(false);
    }
  };

  if (loading || dismissed || !status) return null;

  // N├úo mostrar se est├í tudo OK
  if (!status.bloqueada && !status.vencida && status.dias_vencimento > 7) {
    return null;
  }

  const getBannerStyle = () => {
    if (status.bloqueada || status.vencida) {
      return 'bg-red-600 border-red-700';
    }
    if (status.dias_vencimento <= 3) {
      return 'bg-yellow-600 border-yellow-700';
    }
    return 'bg-blue-600 border-blue-700';
  };

  const getIcon = () => {
    if (status.bloqueada || status.vencida) {
      return <AlertTriangle size={24} className="animate-pulse" />;
    }
    return <AlertTriangle size={24} />;
  };

  const getMessage = () => {
    if (status.bloqueada) {
      return `Ôøö BARBEARIA BLOQUEADA! ${status.motivo_bloqueio}`;
    }
    if (status.vencida) {
      return `ÔÜá´©Å Sua assinatura venceu! Pague R$ ${status.valor_mensalidade?.toFixed(2)} para desbloquear.`;
    }
    if (status.dias_vencimento <= 3) {
      return `ÔÅ░ Sua assinatura vence em ${status.dias_vencimento} dia(s)! Pague antes para evitar bloqueio.`;
    }
    return `­ƒôà Sua assinatura vence em ${status.dias_vencimento} dias.`;
  };

  return (
    <div className={`${getBannerStyle()} border-b text-white shadow-lg`}>
      <div className="container mx-auto px-4 py-3">
        <div className="flex items-center justify-between gap-4">
          <div className="flex items-center gap-3 flex-1">
            {getIcon()}
            <div className="flex-1">
              <p className="font-bold text-sm md:text-base">{getMessage()}</p>
              {status.bloqueada || status.vencida ? (
                <p className="text-xs mt-1 opacity-90">
                  Clique em "Pagar agora" para desbloquear imediatamente.
                </p>
              ) : null}
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={onNavigateToPagamento}
              className="bg-white text-gray-900 font-bold px-4 py-2 rounded-lg hover:bg-gray-100 transition flex items-center gap-2 text-sm"
            >
              <CreditCard size={16} />
              Pagar agora
            </button>
            
            {!status.bloqueada && !status.vencida && (
              <button
                onClick={() => setDismissed(true)}
                className="p-2 hover:bg-white/10 rounded transition"
                title="Dispensar"
              >
                <X size={20} />
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import { Scissors, LogOut, CheckCircle, AlertCircle, Briefcase, User, Calendar, Star, ThumbsUp, MapPin, ArrowRight, Armchair, Wallet } from 'lucide-react';
import AbaPadronizadaAvaliacoes from './AbaPadronizadaAvaliacoes';
import TelaPerfilUsuario from './TelaPerfilUsuario';
import CadeirasDispon├¡veisComponent from './CadeirasDispon├¡veisComponent';

export default function BarberDashboard({ token, logout, notify, API_URL }) {
    const [jobs, setJobs] = useState([]); // Novos chamados - vazio at├® carregar
    const [ongoingJobs, setOngoingJobs] = useState([]); // Atendimentos em andamento
    const [user, setUser] = useState(null);
    const [userData, setUserData] = useState(null);
    const [tab, setTab] = useState('trabalhos'); // 'trabalhos' | 'agenda' | 'aprovar' | 'avaliar' | 'perfil'
    const [loading, setLoading] = useState(true);
    const [presenteNoLocal, setPresenteNoLocal] = useState(false); // Barbeiro presente no local
    const [toggleandoPresenca, setTogandoPresenca] = useState(false); // Enquanto carrega toggle de presen├ºa
    const [statusFreelancer, setStatusFreelancer] = useState('offline'); // 'offline', 'online', 'presente'
    const [barbeariasDisponiveis, setBarbeariasDisponiveis] = useState([]); // Lista de barbearias para selecionar
    const [barbeariaSelecionada, setBarbeariaSelecionada] = useState(null); // Barbearia selecionada para modo presente
    const [mostrarSeletorBarbearia, setMostrarSeletorBarbearia] = useState(false);
    const [cadeirasAcionadas, setCadeirasAcionadas] = useState([]); // Cadeiras dispon├¡veis pr├│ximas
    const [loadingCadeiras, setLoadingCadeiras] = useState(false);
    const [cadeiraOcupada, setCadeiraOcupada] = useState(null); // Cadeira que o barbeiro est├í ocupando

    const sincronizarAgendamentos = useCallback(async () => {
        try {
            setLoading(true);

            const resNovos = await fetch(`${API_URL}/api/v1/chamados/abertos`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const novos = resNovos.ok ? await resNovos.json() : [];
            setJobs(Array.isArray(novos) ? novos : []);

            const resAgendados = await fetch(`${API_URL}/api/v1/barbeiro/agendamentos/meus`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });

            if (resAgendados.ok) {
                const agendados = await resAgendados.json();
                const emAndamento = Array.isArray(agendados)
                    ? agendados.filter(ag => ag.status === 'confirmado')
                    : [];
                setOngoingJobs(emAndamento);
            } else {
                setOngoingJobs([]);
            }
        } catch (err) {
            console.error('Erro ao carregar agendamentos:', err);
            setJobs([]);
            setOngoingJobs([]);
        } finally {
            setLoading(false);
        }
    }, [API_URL, token]);

    // Carregar agendamentos do backend
    useEffect(() => {
        if (token) {
            sincronizarAgendamentos();
            // Recarregar a cada 10 segundos para novos chamados
            const interval = setInterval(sincronizarAgendamentos, 10000);
            return () => clearInterval(interval);
        }
    }, [token, sincronizarAgendamentos]);

    useEffect(() => {
        fetch(`${API_URL}/api/v1/documentos/status`, {
            headers: {'Authorization': `Bearer ${token}`}
        })
        .then(r => r.json())
        .then(data => {
            setUser(data);
            // Carregar status de presen├ºa
            setPresenteNoLocal(data.presente_em_local || false);
            if (!userData) setUserData(data);
        })
        .catch(() => {});

        fetch(`${API_URL}/api/v1/usuarios/perfil-completo`, {
            headers: {'Authorization': `Bearer ${token}`}
        })
        .then(r => {
            if (!r.ok) throw new Error('Erro');
            return r.json();
        })
        .then(data => {
            if (data && data.id) {
                setUserData(data);
                setPresenteNoLocal(data.presente_em_local || false);
                if (data.presente_em_local && data.barbearia_atual_id) {
                    setStatusFreelancer('presente');
                    setBarbeariaSelecionada(data.barbearia_atual_id);
                } else if (data.online_regiao) {
                    setStatusFreelancer('online');
                } else {
                    setStatusFreelancer('offline');
                }
            }
        })
        .catch(() => {});
    }, [API_URL, token]);

    // Carregar cadeiras acionadas pr├│ximas
    const carregarCadeirasAcionadas = async () => {
        try {
            setLoadingCadeiras(true);
            const res = await fetch(`${API_URL}/api/v1/cadeiras/acionadas/proximas`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setCadeirasAcionadas(Array.isArray(data) ? data : []);
            } else {
                setCadeirasAcionadas([]);
            }
        } catch (err) {
            console.error('Erro ao carregar cadeiras:', err);
            setCadeirasAcionadas([]);
        } finally {
            setLoadingCadeiras(false);
        }
    };

    useEffect(() => {
        if (token && tab === 'trabalhos') {
            carregarCadeirasAcionadas();
            // Atualizar a cada 30s
            const interval = setInterval(carregarCadeirasAcionadas, 30000);
            return () => clearInterval(interval);
        }
    }, [API_URL, token, tab]);

    const ocuparCadeira = async (cadeiraId) => {
        try {
            const res = await fetch(`${API_URL}/api/v1/cadeiras/${cadeiraId}/aceitar`, {
                method: 'POST',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            
            if (res.ok) {
                const data = await res.json();
                notify(data.message || 'Ô£à Cadeira bloqueada automaticamente! Agora voc├¬ est├í trabalhando nela.', 'success');
                setCadeiraOcupada(data.cadeira);
                carregarCadeirasAcionadas(); // Recarregar lista
                // Atualizar status para PRESENTE automaticamente
                setStatusFreelancer('presente');
                setPresenteNoLocal(true);
            } else {
                const error = await res.json();
                notify(error.detail || 'Erro ao aceitar cadeira', 'error');
            }
        } catch (err) {
            console.error('Erro:', err);
            notify('Erro ao conectar com servidor', 'error');
        }
    };

    const desocuparCadeira = async () => {
        if (!cadeiraOcupada) return;
        
        try {
            const res = await fetch(`${API_URL}/api/v1/cadeiras/${cadeiraOcupada.id}/desocupar`, {
                method: 'POST',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            
            if (res.ok) {
                const data = await res.json();
                notify(data.message || 'Cadeira liberada com sucesso!', 'success');
                setCadeiraOcupada(null);
                carregarCadeirasAcionadas(); // Recarregar lista
                // Voltar para OFFLINE
                await alterarStatus('offline');
            } else {
                const error = await res.json();
                notify(error.detail || 'Erro ao liberar cadeira', 'error');
            }
        } catch (err) {
            console.error('Erro:', err);
            notify('Erro ao conectar com servidor', 'error');
        }
    };

    const acceptJob = async (id) => {
        try {
            const response = await fetch(`${API_URL}/api/v1/chamados/${id}/aceitar`, {
                method: 'PUT',
                headers: { 'Authorization': `Bearer ${token}` }
            });

            if (response.ok) {
                notify("Trabalho aceito! Ô£ô", "success");
                // Move o job de jobs para ongoingJobs
                const acceptedJob = jobs.find(j => j.id === id);
                if (acceptedJob) {
                    setOngoingJobs(prev => [...prev, { ...acceptedJob, status: 'confirmado' }]);
                }
                setJobs(prevJobs => prevJobs.filter(j => j.id !== id));

                // Sincronizar com backend para evitar inconsist├¬ncia visual
                sincronizarAgendamentos();
            } else {
                const errorData = await response.json().catch(() => ({}));
                notify(errorData.detail || "Erro ao aceitar trabalho", "error");
            }
        } catch (err) {
            notify("Erro ao conectar com servidor", "error");
        }
    };

    const rejectJob = async (id) => {
        try {
            const response = await fetch(`${API_URL}/api/v1/chamados/${id}/rejeitar`, {
                method: 'PUT',
                headers: { 'Authorization': `Bearer ${token}` }
            });

            if (response.ok) {
                notify("Agendamento recusado", "success");
                setJobs(prevJobs => prevJobs.filter(j => j.id !== id));
                sincronizarAgendamentos();
            } else {
                notify("Erro ao recusar agendamento", "error");
            }
        } catch (err) {
            notify("Erro ao conectar com servidor", "error");
        }
    };

    const finalizeJob = async (id) => {
        try {
            const response = await fetch(`${API_URL}/api/v1/chamados/${id}/finalizar`, {
                method: 'PUT',
                headers: { 'Authorization': `Bearer ${token}` }
            });

            if (response.ok) {
                notify("Corte finalizado! Ô£ô", "success");
                setOngoingJobs(prevJobs => prevJobs.filter(j => j.id !== id));
                // Recarrega chamados abertos imediatamente para evitar sumi├ºo visual
                // quando ainda existem solicita├º├Áes pendentes para aceitar/recusar.
                sincronizarAgendamentos();
            } else {
                const errorData = await response.json().catch(() => ({}));
                notify(errorData.detail || "Erro ao finalizar corte", "error");
            }
        } catch (err) {
            notify("Erro ao conectar com servidor", "error");
        }
    };

    // Carregar barbearias dispon├¡veis
    useEffect(() => {
        const carregarBarbearias = async () => {
            try {
                const res = await fetch(`${API_URL}/api/v1/barbearias/proximas?raio_km=50`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                if (res.ok) {
                    const data = await res.json();
                    const lista = Array.isArray(data) ? data : (Array.isArray(data?.barbearias) ? data.barbearias : []);
                    if (lista.length > 0) {
                        setBarbeariasDisponiveis(lista);
                        return;
                    }
                }

                // Fallback para quando n├úo h├í localiza├º├úo cadastrada no perfil
                const fallbackRes = await fetch(`${API_URL}/api/v1/barbearias/todas-aprovadas`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                if (fallbackRes.ok) {
                    const fallbackData = await fallbackRes.json();
                    const fallbackLista = Array.isArray(fallbackData)
                        ? fallbackData
                        : (Array.isArray(fallbackData?.barbearias) ? fallbackData.barbearias : []);
                    setBarbeariasDisponiveis(fallbackLista);
                } else {
                    setBarbeariasDisponiveis([]);
                }
            } catch (err) {
                console.error('Erro ao carregar barbearias:', err);
                setBarbeariasDisponiveis([]);
            }
        };
        if (token) carregarBarbearias();
    }, [API_URL, token]);

    // Fun├º├úo para alterar status do freelancer
    const alterarStatus = async (novoStatus, barbeariaId = null) => {
        try {
            setTogandoPresenca(true);
            
            // Mapear status do frontend para backend
            const statusMap = {
                'offline': 'offline',
                'online': 'online_region',
                'presente': 'present_local'
            };
            
            const statusBackend = statusMap[novoStatus] || novoStatus;
            
            const response = await fetch(`${API_URL}/api/v1/barbeiro/status`, {
                method: 'PUT',
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    status: statusBackend,
                    barbearia_id: barbeariaId
                })
            });

            if (response.ok) {
                const data = await response.json();
                setStatusFreelancer(novoStatus);
                setPresenteNoLocal(data.presente_em_local);
                setBarbeariaSelecionada(data.barbearia_atual_id || barbeariaId || null);
                
                const mensagens = {
                    'offline': '­ƒÿ┤ Voc├¬ est├í OFFLINE (n├úo recebe chamados)',
                    'online': '­ƒîì Voc├¬ est├í ONLINE (recebe chamados da regi├úo)',
                    'presente': `­ƒÅó Voc├¬ est├í PRESENTE na barbearia`
                };
                
                notify(mensagens[novoStatus] || 'Status atualizado', 'success');
                setMostrarSeletorBarbearia(false);
                sincronizarAgendamentos();
            } else {
                const error = await response.json().catch(() => ({}));
                notify(error.detail || 'Erro ao alterar status', 'error');
            }
        } catch (err) {
            console.error('Erro:', err);
            notify('Erro ao conectar com servidor', 'error');
        } finally {
            setTogandoPresenca(false);
        }
    };

    const togglePresenca = async () => {
        // Mantido para compatibilidade com c├│digo legado
        await alterarStatus(presenteNoLocal ? 'offline' : 'online');
    };

    return (
        <div className="bg-black h-full w-full max-w-full overflow-hidden flex flex-col text-white font-sans">
            {/* HEADER FIXO */}
            <div className="p-2 sm:p-4 flex justify-between items-center border-b border-zinc-800 bg-black/80 backdrop-blur-md z-20 flex-shrink-0">
                <div className="flex items-center gap-2">
                    <h1 className="text-base sm:text-xl font-bold flex items-center gap-2">
                        <Scissors size={18} className="text-orange-500"/> Barbeiro
                    </h1>
                    {user?.documento_verificado && (
                        <CheckCircle size={14} className="text-blue-500 fill-blue-500" />
                    )}
                </div>
                <button onClick={logout} className="text-zinc-500 hover:text-white"><LogOut size={18}/></button>
            </div>

            {/* CONTE├ÜDO PRINCIPAL - S├ô UMA ABA DE CADA VEZ */}
            <div className="flex-1 overflow-y-auto pb-16">
                
                {/* === ABA 1: TRABALHOS === */}
                {tab === 'trabalhos' && (
                    <div className="p-2 sm:p-4 space-y-3">
                        {/* ­ƒöÿ 3 BOT├òES DE STATUS */}
                        <div className="bg-zinc-900/50 border border-zinc-800 p-3 rounded-lg space-y-2">
                            <h3 className="text-xs font-bold text-zinc-400 uppercase mb-2">Status Operacional</h3>
                            
                            <div className="grid grid-cols-3 gap-2">
                                {/* OFFLINE */}
                                <button
                                    onClick={() => alterarStatus('offline')}
                                    disabled={toggleandoPresenca}
                                    className={`py-2 px-3 rounded-lg font-bold text-xs transition flex flex-col items-center justify-center gap-1 ${
                                        statusFreelancer === 'offline'
                                            ? 'bg-red-600 text-white border-2 border-red-400'
                                            : 'bg-zinc-800 text-zinc-400 border border-zinc-700 hover:bg-zinc-700'
                                    } ${toggleandoPresenca ? 'opacity-50 cursor-not-allowed' : ''}`}
                                >
                                    <div className={`h-2 w-2 rounded-full ${statusFreelancer === 'offline' ? 'bg-white' : 'bg-zinc-600'}`}></div>
                                    OFFLINE
                                </button>

                                {/* DISPON├ìVEL */}
                                <button
                                    onClick={() => statusFreelancer === 'presente' ? alterarStatus('presente', barbeariaSelecionada) : alterarStatus('online')}
                                    disabled={toggleandoPresenca}
                                    className={`py-2 px-3 rounded-lg font-bold text-xs transition flex flex-col items-center justify-center gap-1 ${
                                        statusFreelancer === 'online' || statusFreelancer === 'presente'
                                            ? 'bg-green-600 text-white border-2 border-green-400'
                                            : 'bg-zinc-800 text-zinc-400 border border-zinc-700 hover:bg-zinc-700'
                                    } ${toggleandoPresenca ? 'opacity-50 cursor-not-allowed' : ''}`}
                                >
                                    <div className={`h-2 w-2 rounded-full ${statusFreelancer === 'online' || statusFreelancer === 'presente' ? 'bg-white animate-pulse' : 'bg-zinc-600'}`}></div>
                                    {statusFreelancer === 'presente' ? 'DISPON├ìVEL AQUI' : 'DISPON├ìVEL'}
                                </button>

                                {/* PRESENTE ou SAIR */}
                                {statusFreelancer === 'presente' ? (
                                    <button
                                        onClick={() => alterarStatus('online')}
                                        disabled={toggleandoPresenca}
                                        className={`py-2 px-3 rounded-lg font-bold text-xs transition flex flex-col items-center justify-center gap-1 bg-yellow-600 hover:bg-yellow-700 text-white border-2 border-yellow-400 ${toggleandoPresenca ? 'opacity-50 cursor-not-allowed' : ''}`}
                                    >
                                        <div className="h-2 w-2 rounded-full bg-white"></div>
                                        SAIR
                                    </button>
                                ) : (
                                    <button
                                        onClick={() => setMostrarSeletorBarbearia(true)}
                                        disabled={toggleandoPresenca}
                                        className={`py-2 px-3 rounded-lg font-bold text-xs transition flex flex-col items-center justify-center gap-1 ${
                                            statusFreelancer === 'presente'
                                                ? 'bg-blue-600 text-white border-2 border-blue-400'
                                                : 'bg-zinc-800 text-zinc-400 border border-zinc-700 hover:bg-zinc-700'
                                        } ${toggleandoPresenca ? 'opacity-50 cursor-not-allowed' : ''}`}
                                    >
                                        <div className={`h-2 w-2 rounded-full ${statusFreelancer === 'presente' ? 'bg-white animate-pulse' : 'bg-zinc-600'}`}></div>
                                        PRESENTE
                                    </button>
                                )}
                            </div>

                            {/* Indicador de status atual */}
                            <div className="text-center mt-2 p-2 bg-zinc-800/50 rounded">
                                <p className="text-xs text-zinc-300">
                                    {statusFreelancer === 'offline' && '­ƒö┤ N├úo recebe chamados'}
                                    {statusFreelancer === 'online' && '­ƒƒó Dispon├¡vel para trabalhar em qualquer barbearia'}
                                    {statusFreelancer === 'presente' && '­ƒöÁ Trabalhando em uma barbearia espec├¡fica'}
                                </p>
                            </div>

                            {toggleandoPresenca && (
                                <div className="flex items-center justify-center gap-2 py-2">
                                    <div className="w-4 h-4 border-2 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
                                    <span className="text-xs text-zinc-400">Atualizando status...</span>
                                </div>
                            )}
                        </div>

                        {/* ­ƒôì CADEIRAS ACIONADAS PR├ôXIMAS */}
                        <div className="bg-zinc-900/50 border border-zinc-800 p-3 rounded-lg">
                            <h3 className="text-xs font-bold text-zinc-400 uppercase mb-2 flex items-center gap-2">
                                <MapPin size={14} className="text-green-500" />
                                Cadeiras Dispon├¡veis Pr├│ximas
                            </h3>
                            
                            {/* Se j├í ocupou uma cadeira */}
                            {cadeiraOcupada && (
                                <div className="bg-green-900/20 border border-green-700 rounded-lg p-3 mb-3">
                                    <div className="flex items-start justify-between gap-2">
                                        <div className="flex-1">
                                            <p className="text-xs font-bold text-green-400 mb-1">Ô£ô Voc├¬ est├í na cadeira {cadeiraOcupada.numero}</p>
                                            <p className="text-xs text-zinc-300">{cadeiraOcupada.barbearia_nome}</p>
                                            <p className="text-[10px] text-zinc-500">{cadeiraOcupada.barbearia_endereco}</p>
                                        </div>
                                        <button
                                            onClick={desocuparCadeira}
                                            className="px-3 py-1.5 bg-red-600 hover:bg-red-700 rounded text-xs font-bold active:scale-95"
                                        >
                                            Sair
                                        </button>
                                    </div>
                                </div>
                            )}
                            
                            {loadingCadeiras ? (
                                <div className="flex items-center justify-center gap-2 py-4">
                                    <div className="w-4 h-4 border-2 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
                                    <span className="text-xs text-zinc-400">Buscando cadeiras...</span>
                                </div>
                            ) : cadeirasAcionadas.length === 0 ? (
                                <div className="text-center py-4">
                                    <p className="text-xs text-zinc-500 mb-1">­ƒôì Nenhuma cadeira acionada pr├│xima</p>
                                    <p className="text-[10px] text-zinc-600">Barbearias n├úo acionaram cadeiras nas ├║ltimas 24h (raio 10km)</p>
                                </div>
                            ) : (
                                <div className="space-y-2">
                                    {cadeirasAcionadas.slice(0, 5).map(cadeira => (
                                        <div key={cadeira.id} className="bg-zinc-800/50 border border-zinc-700 rounded-lg p-2.5">
                                            <div className="flex items-start justify-between gap-2">
                                                <div className="flex-1">
                                                    <p className="text-xs font-bold text-white mb-0.5">
                                                        Cadeira {cadeira.numero} - {cadeira.barbearia_nome}
                                                    </p>
                                                    <p className="text-[10px] text-zinc-400 mb-1">{cadeira.barbearia_endereco}</p>
                                                    <div className="flex items-center gap-2">
                                                        {cadeira.distancia_km && (
                                                            <span className="text-[10px] text-green-400 font-bold">
                                                                ­ƒôì {cadeira.distancia_km} km
                                                            </span>
                                                        )}
                                                        <span className="text-[10px] text-zinc-500">
