                {/* === ABA 4: AVALIAR === */}
                {tab === 'avaliar' && (
                    <div className="p-2 sm:p-4 pb-20">
                        {userData ? (
                            <AbaPadronizadaAvaliacoes
                                usuarioId={userData.id}
