                        tab === 'cadeiras' ? 'text-orange-500 bg-orange-500/5' : 'text-zinc-500 hover:text-zinc-400'
                    }`}
                >
                    <Armchair size={14} />
                    <span className="text-[7px] font-bold">Cadeiras</span>
                </button>

                <button
