}

/**
 * Componente: CadastroServicosOnboarding
 * Localiza├º├úo: barbermove/src/components/CadastroServicosOnboarding.jsx
 * 
 * Fluxo:
 * 1. Dono abre o app
 * 2. V├¬ a tela: "Vamos configurar sua loja! Quais servi├ºos voc├¬ oferece?"
 * 3. Clica em "Adicionar Servi├ºo"
 * 4. V├¬ sugest├Áes (Corte, Barba, Combo, etc)
 * 5. Clica em uma sugest├úo
 * 6. App preenche os campos (nome, dura├º├úo, pre├ºo padr├úo)
 * 7. Dono edita o pre├ºo se quiser (ex: quer cobrar R$ 40 em vez de R$ 30)
 * 8. Clica em "Salvar Servi├ºo"
 * 9. Servi├ºo fica salvo com os valores personalizados dele
 */

import { useState, useEffect } from 'react';
import SeletorCategoria from './SeletorCategoria';

export const CadastroServicosOnboarding = ({ barbearia_id, token, apiUrl }) => {
  const [servicos, setServicos] = useState([]);
  const [templates, setTemplates] = useState([]);
  const [mostraFormulario, setMostraFormulario] = useState(false);
  const [servicoSelecionado, setServicoSelecionado] = useState(null);
  const [formulario, setFormulario] = useState({
    nome: '',
    categoria: '',
    descricao: '',
    valor: '',
    duracao_minutos: 30
  });
  const [loading, setLoading] = useState(false);

  // Carregar templates
  useEffect(() => {
    fetch(`${apiUrl}/templates/servicos`)
      .then(r => r.json())
      .then(data => setTemplates(data.templates))
      .catch(err => {
        // Erro ao carregar servi├ºos
      });
  }, [apiUrl]);

  // Carregar servi├ºos existentes
  const carregarServicos = async () => {
    try {
      const response = await fetch(
        `${apiUrl}/barbearias/${barbearia_id}/servicos`,
        { headers: { 'Authorization': `Bearer ${token}` } }
      );
      const data = await response.json();
      setServicos(data.servicos);
    } catch (error) {
      // Erro ao carregar servi├ºos
    }
  };

  useEffect(() => {
    carregarServicos();
  }, [barbearia_id, token, apiUrl]);

  // Ô£à Usu├írio clica em um template
  const handleSelecionarTemplate = (template) => {
    // Pre-preencher formul├írio com valores do template
    setServicoSelecionado(template);
    setFormulario({
      nome: template.nome,
      categoria: template.categoria,  // Ô£à H├ìBRIDO: categoria vem do template
      descricao: template.descricao,
      valor: template.valor_padrao.toString(),
      duracao_minutos: template.duracao_minutos_padrao
    });
    setMostraFormulario(true);
  };

  // Ô£à Usu├írio edita o valor antes de salvar
  const handleMudarValor = (novoValor) => {
    setFormulario({
      ...formulario,
      valor: novoValor
    });
  };

  // Ô£à Salvar novo servi├ºo
  const handleSalvarServico = async () => {
    if (!formulario.nome || !formulario.valor || !formulario.categoria) {
      alert('Nome, categoria e valor s├úo obrigat├│rios');
      return;
    }

    setLoading(true);
    try {
      const response = await fetch(
        `${apiUrl}/barbearias/${barbearia_id}/servicos`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
          },
          body: JSON.stringify({
            nome: formulario.nome,
            categoria: formulario.categoria,  // Ô£à Envia categoria
            descricao: formulario.descricao,
            valor: parseFloat(formulario.valor),
            duracao_minutos: parseInt(formulario.duracao_minutos)
          })
        }
      );

      if (response.ok) {
        const data = await response.json();
        alert(`Ô£à ${data.mensagem}`);
        
        // Limpar formul├írio e recarregar servi├ºos
        setMostraFormulario(false);
        setServicoSelecionado(null);
        carregarServicos();
      } else {
        const erro = await response.json();
        alert(`ÔØî Erro: ${erro.detail}`);
      }
    } catch (error) {
      alert(`ÔØî Erro ao salvar: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-4">
      {/* Cabe├ºalho */}
      <div className="mb-6">
        <h1 className="text-3xl font-bold mb-2">­ƒÅ¬ Vamos Configurar Sua Loja!</h1>
        <p className="text-gray-600">
          Quais servi├ºos voc├¬ oferece? Voc├¬ pode editar tudo depois.
        </p>
      </div>

      {/* Lista de servi├ºos j├í criados */}
      {servicos.length > 0 && (
        <div className="bg-green-50 border border-green-200 rounded-lg p-4 mb-6">
          <h3 className="font-bold text-green-800 mb-3">Ô£à Seus Servi├ºos</h3>
          <div className="space-y-2">
            {servicos.map(s => (
              <div key={s.id} className="flex justify-between items-center bg-white p-3 rounded border border-green-100">
                <div>
                  <p className="font-semibold">{s.nome}</p>
                  <p className="text-sm text-gray-500">{s.duracao_minutos} min</p>
                </div>
                <div className="text-right">
                  <p className="text-lg font-bold text-green-600">R$ {s.valor.toFixed(2)}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Bot├úo para adicionar mais */}
      {!mostraFormulario && (
        <button
          onClick={() => setMostraFormulario(true)}
          className="w-full bg-blue-600 text-white py-3 rounded-lg font-bold text-lg hover:bg-blue-700 mb-4"
        >
          Ô×ò Adicionar Servi├ºo
        </button>
      )}

      {/* Formul├írio aberto */}
      {mostraFormulario && !servicoSelecionado && (
        <div className="border-2 border-blue-300 rounded-lg p-6 mb-4 bg-blue-50">
          <h2 className="text-2xl font-bold mb-4">Escolha um Template</h2>
          <p className="text-gray-600 mb-4">
            Clique em um dos servi├ºos abaixo. O app vai preencher os campos com valores sugeridos.
            Voc├¬ pode editar tudo antes de salvar! ­ƒÆí
          </p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            {templates.map((template, idx) => (
              <button
                key={idx}
                onClick={() => handleSelecionarTemplate(template)}
                className="text-left p-4 border-2 border-blue-200 rounded-lg hover:border-blue-600 hover:bg-blue-100 transition"
              >
                <h4 className="font-bold text-blue-900">{template.nome}</h4>
                <p className="text-sm text-gray-600 mt-1">{template.descricao}</p>
                <div className="flex justify-between items-center mt-3">
                  <span className="text-sm text-gray-500">ÔÅ▒ {template.duracao_minutos_padrao} min</span>
                  <span className="text-lg font-bold text-blue-600">
                    R$ {template.valor_padrao.toFixed(2)}
                  </span>
                </div>
              </button>
            ))}
          </div>

          <button
            onClick={() => setMostraFormulario(false)}
            className="w-full mt-4 bg-gray-300 text-gray-800 py-2 rounded hover:bg-gray-400"
          >
            Cancelar
          </button>
        </div>
      )}

      {/* Formul├írio com template pr├®-preenchido */}
      {mostraFormulario && servicoSelecionado && (
        <div className="border-2 border-green-300 rounded-lg p-6 bg-green-50">
          <h2 className="text-2xl font-bold mb-4">
            Ô£Å´©Å Personalize seu servi├ºo: {servicoSelecionado.nome}
          </h2>

          {/* Nome */}
          <div className="mb-4">
            <label className="block text-sm font-bold mb-2">Nome do Servi├ºo</label>
            <input
              type="text"
              value={formulario.nome}
              onChange={(e) => setFormulario({ ...formulario, nome: e.target.value })}
              className="w-full border-2 border-gray-300 rounded px-3 py-2 font-semibold"
            />
          </div>

          {/* Descri├º├úo */}
          <div className="mb-4">
            <label className="block text-sm font-bold mb-2">Descri├º├úo (Opcional)</label>
            <textarea
              value={formulario.descricao}
              onChange={(e) => setFormulario({ ...formulario, descricao: e.target.value })}
              className="w-full border-2 border-gray-300 rounded px-3 py-2"
              rows="2"
              placeholder="Ex: Inclui corte na m├íquina e tesoura"
            />
          </div>

          {/* Pre├ºo (O IMPORTANTE!) */}
          <div className="mb-4 p-4 bg-yellow-100 border-2 border-yellow-400 rounded">
            <label className="block text-sm font-bold mb-2">­ƒÆ░ Pre├ºo</label>
            <div className="flex items-center">
              <span className="text-2xl mr-2">R$</span>
              <input
                type="number"
                step="0.01"
                min="0"
                value={formulario.valor}
                onChange={(e) => handleMudarValor(e.target.value)}
                className="flex-1 border-2 border-yellow-400 rounded px-3 py-2 text-2xl font-bold"
              />
            </div>
            <p className="text-xs text-gray-600 mt-2">
              ­ƒôî Sugest├úo: R$ {servicoSelecionado.valor_padrao.toFixed(2)} (mas voc├¬ pode mudar!)
            </p>
          </div>

          {/* Dura├º├úo */}
          <div className="mb-6">
            <label className="block text-sm font-bold mb-2">ÔÅ▒ Dura├º├úo (minutos)</label>
            <div className="flex gap-2 flex-wrap">
              {[15, 20, 30, 40, 50, 60].map(min => (
                <button
                  key={min}
                  onClick={() => setFormulario({ ...formulario, duracao_minutos: min })}
                  className={`px-4 py-2 rounded font-semibold transition ${
                    formulario.duracao_minutos === min
                      ? 'bg-green-600 text-white'
                      : 'bg-gray-200 hover:bg-gray-300'
                  }`}
                >
                  {min} min
                </button>
              ))}
            </div>
          </div>

          {/* Bot├Áes */}
          <div className="flex gap-3">
            <button
              onClick={handleSalvarServico}
              disabled={loading}
