                            {ehAgendamentoAgora && (
                                <div className="bg-green-900/30 border-2 border-green-500 rounded-lg p-3 text-center">
                                    <p className="text-green-400 font-bold text-sm">­ƒÜÇ AGENDAMENTO EM TEMPO REAL</p>
                                    <p className="text-xs text-green-300 mt-1">{selectedBarber?.nome} est├í PRESENTE na barbearia!</p>
                                    <p className="text-xs text-green-300">Vai receber seu chamado AGORA</p>
