      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center p-4">
        <div className="max-w-4xl w-full">
          <div className="text-center mb-8">
            <h1 className="text-4xl font-bold text-gray-900 mb-2">BarberMovie</h1>
            <p className="text-gray-600">Conectando barbearias, freelancers e clientes</p>
          </div>

          <div className="grid md:grid-cols-3 gap-6">
            {userTypes.map(({ type, title, description, icon: Icon, color }) => {
              const colors = {
                blue: 'from-blue-500 to-blue-600 hover:from-blue-600 hover:to-blue-700',
                green: 'from-green-500 to-green-600 hover:from-green-600 hover:to-green-700',
                purple: 'from-purple-500 to-purple-600 hover:from-purple-600 hover:to-purple-700',
              };

              return (
                <div
                  key={type}
                  onClick={() => handleTypeSelect(type)}
                  className={`bg-gradient-to-br ${colors[color]} text-white rounded-2xl p-6 cursor-pointer transform transition-all hover:scale-105 hover:shadow-xl`}
                >
                  <Icon size={48} className="mb-4" />
                  <h2 className="text-2xl font-bold mb-2">{title}</h2>
                  <p className="text-white/90">{description}</p>
                  <div className="mt-4 flex items-center text-sm font-semibold">
                    <span>Entrar</span>
                    <ArrowRight size={16} className="ml-1" />
                  </div>
                </div>
              );
            })}
          </div>

          <div className="text-center mt-8">
            <p className="text-gray-600">
              N├úo tem conta?{' '}
              <button onClick={() => setStep('cadastro')} className="text-blue-600 font-semibold hover:underline">
                Cadastre-se
              </button>
            </p>
          </div>
        </div>
      </div>
    );
  }

  if (step === 'login') {
    const selectedUserType = userTypes.find(t => t.type === selectedType);

    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-xl p-8 max-w-md w-full">
          <button
            onClick={() => setStep('escolha')}
            className="text-gray-600 hover:text-gray-900 mb-4 flex items-center"
          >
            ÔåÉ Voltar
          </button>

          <div className="text-center mb-6">
            <selectedUserType.icon size={48} className="mx-auto mb-2 text-blue-600" />
            <h2 className="text-2xl font-bold">{selectedUserType.title}</h2>
            <p className="text-gray-600 mt-1">{selectedUserType.description}</p>
          </div>

          <form onSubmit={handleLogin}>
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="seu@email.com"
              required
            />

            <Input
              label="Senha"
              type="password"
              value={senha}
              onChange={(e) => setSenha(e.target.value)}
              placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
              required
            />

            <Button type="submit" fullWidth disabled={loading}>
              {loading ? 'Entrando...' : 'Entrar'}
            </Button>
          </form>

          <div className="mt-6 text-center">
            <button className="text-sm text-blue-600 hover:underline">
              Esqueci minha senha
            </button>
          </div>

          <div className="mt-4 text-center">
            <p className="text-gray-600 text-sm">
              N├úo tem conta?{' '}
              <button onClick={() => setStep('cadastro')} className="text-blue-600 font-semibold hover:underline">
                Cadastre-se
              </button>
            </p>
          </div>
        </div>
      </div>
    );
  }

  return null;
}

import React, { useState, useEffect } from 'react';
import { TrendingUp, DollarSign, Calendar, BarChart3, Download, Filter, ChevronDown, CreditCard, Wallet, Clock, TrendingDown, Eye, EyeOff, RefreshCw } from 'lucide-react';

const API_URL = import.meta.env.VITE_API_URL || "http://localhost:8000";

/**
 * Componente de Pagamento/Recebimento para Barbeiro e Barbearia
 */
export default function PaymentSection({ userType, token, onNotify }) {
  const [dados, setDados] = useState(null);
  const [loading, setLoading] = useState(true);
  const [transacoes, setTransacoes] = useState([]);
  const [saldoDetalhado, setSaldoDetalhado] = useState(null);
  const [filtro, setFiltro] = useState('todos'); // 'todos', 'credito', 'debito', 'saque'
  const [periodo, setPeriodo] = useState('30dias'); // '7dias', '30dias', '90dias', 'ano'
  const [mostrarSaldo, setMostrarSaldo] = useState(true);
  const [expandido, setExpandido] = useState(null);
  const [metodoPreferido, setMetodoPreferido] = useState('pix');

  useEffect(() => {
    if (userType === 'cliente') {
      const salvo = localStorage.getItem('cliente_metodo_pagamento_preferido');
      if (salvo === 'pix' || salvo === 'cartao_credito' || salvo === 'cartao_debito') {
        setMetodoPreferido(salvo);
      } else {
        setMetodoPreferido('pix');
      }
    }
  }, [userType]);

  const formatarDataCurta = (iso) => {
    if (!iso) return '';
    const data = new Date(iso);
    if (Number.isNaN(data.getTime())) return '';
    return data.toLocaleDateString('pt-BR');
  };

  const formatarDataCompleta = (iso) => {
    if (!iso) return '';
    const data = new Date(iso);
    if (Number.isNaN(data.getTime())) return '';
    return data.toLocaleDateString('pt-BR', { 
      day: '2-digit', 
      month: 'long', 
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  useEffect(() => {
    carregarDadosPagamento();
  }, [periodo]);

  const carregarDadosPagamento = async () => {
    try {
      setLoading(true);
      
      // Buscar saldo - com fallback para dados dummy mais completos
      const totalBruto = 5389.00; // Total ganho bruto
      const comissaoPlataforma = totalBruto * 0.10; // 10% de comiss├úo
      const totalLiquido = totalBruto - comissaoPlataforma;
      
      let saldoData = {
        saldo_disponivel: 1250.00,
        saldo_em_retencao: 380.00,
        total_ganho: totalLiquido, // Total l├¡quido ap├│s comiss├úo
        total_bruto: totalBruto, // Total bruto antes da comiss├úo
        comissao_paga: comissaoPlataforma, // 10% do total bruto
        total_saques: 2735.00,
        media_por_servico: 75.50,
        servicos_mes: 18
      };

      // Buscar transa├º├Áes recentes com mais detalhes
      const hoje = new Date();
      let transacoes_dummy = [
        { 
          id: 1, 
          descricao: "Corte + Barba Premium", 
          valor: 85.00, 
          data: new Date(hoje - 3600000).toISOString(), 
          tipo: 'credito',
          status: 'concluido',
          cliente: 'Jo├úo Silva',
          metodo: 'pix'
        },
        { 
          id: 2, 
          descricao: "Corte de cabelo + Sobrancelha", 
          valor: 65.00, 
          data: new Date(hoje - 7200000).toISOString(), 
          tipo: 'credito',
          status: 'concluido',
          cliente: 'Pedro Santos',
          metodo: 'cartao'
        },
        { 
          id: 3, 
          descricao: "Saque realizado", 
          valor: 500.00, 
          data: new Date(hoje - 86400000 * 2).toISOString(), 
          tipo: 'debito',
          status: 'processando',
          metodo: 'transferencia'
        },
        { 
          id: 4, 
          descricao: "Pigmenta├º├úo de barba", 
          valor: 95.00, 
          data: new Date(hoje - 86400000 * 2).toISOString(), 
          tipo: 'credito',
          status: 'concluido',
          cliente: 'Carlos Mendes',
          metodo: 'dinheiro'
        },
        { 
          id: 5, 
          descricao: "Corte infantil", 
          valor: 40.00, 
          data: new Date(hoje - 86400000 * 3).toISOString(), 
          tipo: 'credito',
          status: 'concluido',
          cliente: 'Maria Oliveira',
          metodo: 'pix'
        },
        { 
          id: 6, 
          descricao: "Hidrata├º├úo + Corte", 
          valor: 120.00, 
          data: new Date(hoje - 86400000 * 4).toISOString(), 
          tipo: 'credito',
          status: 'em_retencao',
          cliente: 'Rafael Costa',
          metodo: 'cartao'
        },
        { 
          id: 7, 
          descricao: "Barba completa", 
          valor: 50.00, 
          data: new Date(hoje - 86400000 * 5).toISOString(), 
          tipo: 'credito',
          status: 'concluido',
          cliente: 'Lucas Ferreira',
          metodo: 'pix'
        }
      ];

      setDados(saldoData);
      setSaldoDetalhado({
        saldoDisponivel: saldoData.saldo_disponivel,
        saldoEmRetencao: saldoData.saldo_em_retencao,
        totalGanho: saldoData.total_ganho,
        totalBruto: saldoData.total_bruto,
        comissaoPaga: saldoData.comissao_paga,
        totalSaques: saldoData.total_saques,
        mediaPorServico: saldoData.media_por_servico,
        servicosMes: saldoData.servicos_mes,
        proximoSaque: new Date(Date.now() + 259200000).toISOString()
      });
      setTransacoes(transacoes_dummy);
    } catch (err) {
      onNotify?.('Erro ao carregar dados de pagamento', 'error');
    } finally {
      setLoading(false);
    }
  };

  const solicitarSaque = async () => {
    if (!saldoDetalhado?.saldoDisponivel || saldoDetalhado.saldoDisponivel < 50) {
      onNotify('Saldo m├¡nimo de R$ 50 necess├írio para saque', 'warning');
      return;
    }

    try {
      const res = await fetch(`${API_URL}/api/v1/saques/solicitar`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}` 
        },
        body: JSON.stringify({ 
          valor: saldoDetalhado.saldoDisponivel,
          banco: 'A DEFINIR',
          agencia: '0001',
          conta: '000000-0',
          tipo_conta: 'corrente'
        })
      });

      if (res.ok) {
        onNotify('Saque solicitado com sucesso! Voc├¬ receber├í em 2-3 dias ├║teis', 'success');
        carregarDadosPagamento();
      } else {
        const error = await res.json();
        onNotify(error.detail || 'Erro ao solicitar saque', 'error');
      }
    } catch (err) {
      onNotify('Erro ao processar saque', 'error');
    }
  };

  const exportarExtrato = () => {
    const transacoesFiltradas = transacoes.filter(t => {
      if (filtro === 'todos') return true;
      if (filtro === 'credito') return t.tipo === 'credito';
      if (filtro === 'debito') return t.tipo === 'debito';
      if (filtro === 'saque') return t.descricao.toLowerCase().includes('saque');
      return true;
    });

    const csv = [
      ['Data', 'Descri├º├úo', 'Cliente', 'M├®todo', 'Tipo', 'Status', 'Valor'].join(';'),
      ...transacoesFiltradas.map(t => [
        formatarDataCompleta(t.data),
        t.descricao,
        t.cliente || '-',
        t.metodo || '-',
        t.tipo,
        t.status || '-',
        `R$ ${t.valor.toFixed(2)}`
      ].join(';'))
    ].join('\n');

    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `extrato_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    
    onNotify('Extrato exportado com sucesso!', 'success');
  };

  const transacoesFiltradas = transacoes.filter(t => {
    if (filtro === 'todos') return true;
    if (filtro === 'credito') return t.tipo === 'credito' || t.tipo === 'entrada';
    if (filtro === 'debito') return t.tipo === 'debito' || t.tipo === 'saida';
    if (filtro === 'saque') return t.descricao.toLowerCase().includes('saque');
    return true;
  });

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <div className="text-center space-y-4">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-green-500 mx-auto"></div>
          <div className="text-zinc-400">Carregando informa├º├Áes financeiras...</div>
        </div>
      </div>
    );
  }

  const nomeSecao = userType === 'cliente' ? 'Pagamentos' : userType === 'barbeiro' ? 'Meus Ganhos' : 'Recebimentos';

  if (userType === 'cliente') {
    return (
      <div className="space-y-4 pb-24">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-gradient-to-br from-green-500 to-emerald-500 p-3 rounded-2xl shadow-lg">
              <DollarSign size={24} className="text-white" />
            </div>
            <div>
              <h2 className="text-xl font-bold text-white">{nomeSecao}</h2>
              <p className="text-xs text-zinc-400">Forma de pagamento do cliente</p>
            </div>
          </div>
        </div>

        <div className="bg-gradient-to-br from-zinc-900/80 to-zinc-900/40 rounded-2xl p-5 border border-zinc-800">
          <div className="flex items-center gap-2 mb-4">
            <CreditCard size={20} className="text-orange-400" />
            <h3 className="text-lg font-bold text-white">Formas de Pagamento</h3>
          </div>

          <button
            onClick={() => {
              setMetodoPreferido('pix');
              localStorage.setItem('cliente_metodo_pagamento_preferido', 'pix');
              onNotify?.('PIX definido como forma de pagamento.', 'success');
            }}
            className={`w-full rounded-lg px-3 py-3 text-sm font-bold border transition ${metodoPreferido === 'pix' ? 'bg-emerald-500/20 border-emerald-500 text-emerald-300' : 'bg-zinc-800 border-zinc-700 text-zinc-300 hover:bg-zinc-700'}`}
          >
            PIX
          </button>

          <button
            onClick={() => {
              setMetodoPreferido('cartao_credito');
              localStorage.setItem('cliente_metodo_pagamento_preferido', 'cartao_credito');
              onNotify?.('Cartao de Credito definido como forma de pagamento.', 'success');
            }}
            className={`w-full rounded-lg px-3 py-3 text-sm font-bold border transition mt-2 ${metodoPreferido === 'cartao_credito' ? 'bg-blue-500/20 border-blue-500 text-blue-300' : 'bg-zinc-800 border-zinc-700 text-zinc-300 hover:bg-zinc-700'}`}
          >
            Cartao de Credito
          </button>

          <button
            onClick={() => {
              setMetodoPreferido('cartao_debito');
              localStorage.setItem('cliente_metodo_pagamento_preferido', 'cartao_debito');
              onNotify?.('Cartao de Debito definido como forma de pagamento.', 'success');
            }}
            className={`w-full rounded-lg px-3 py-3 text-sm font-bold border transition mt-2 ${metodoPreferido === 'cartao_debito' ? 'bg-indigo-500/20 border-indigo-500 text-indigo-300' : 'bg-zinc-800 border-zinc-700 text-zinc-300 hover:bg-zinc-700'}`}
          >
            Cartao de Debito
          </button>

          <p className="text-xs text-zinc-400 mt-3">
            Metodo selecionado: <span className="text-zinc-200 font-bold">{metodoPreferido.replace('_', ' ')}</span>. Use esta forma na finalizacao do pagamento do atendimento.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 pb-24">
      {/* Cabe├ºalho */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="bg-gradient-to-br from-green-500 to-emerald-500 p-3 rounded-2xl shadow-lg">
            <DollarSign size={28} className="text-white" />
          </div>
          <div>
            <h2 className="text-2xl font-bold text-white">{nomeSecao}</h2>
            <p className="text-xs text-zinc-400">Gest├úo financeira completa</p>
          </div>
        </div>
        <button
          onClick={carregarDadosPagamento}
          className="bg-zinc-800 hover:bg-zinc-700 text-white p-3 rounded-xl transition"
          title="Atualizar dados"
        >
          <RefreshCw size={20} />
        </button>
      </div>

      {/* Cards de Resumo Financeiro */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        {/* Saldo Dispon├¡vel */}
        <div className="bg-gradient-to-br from-green-500/20 to-emerald-500/10 rounded-2xl p-6 border border-green-500/30 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-green-500/10 rounded-full -mr-16 -mt-16"></div>
          <div className="relative">
            <div className="flex items-center justify-between mb-3">
              <p className="text-xs text-green-400 font-bold uppercase tracking-wide flex items-center gap-2">
                <Wallet size={16} />
                Dispon├¡vel para Saque
              </p>
              <button
                onClick={() => setMostrarSaldo(!mostrarSaldo)}
                className="text-green-400 hover:text-green-300 transition"
              >
                {mostrarSaldo ? <Eye size={16} /> : <EyeOff size={16} />}
              </button>
            </div>
            <p className="text-3xl font-bold text-white mb-4">
              {mostrarSaldo ? `R$ ${(saldoDetalhado?.saldoDisponivel || 0).toFixed(2)}` : 'R$ ÔÇóÔÇóÔÇóÔÇóÔÇó'}
            </p>
            <button
              onClick={solicitarSaque}
              disabled={!saldoDetalhado?.saldoDisponivel || saldoDetalhado.saldoDisponivel < 50}
              className="w-full bg-gradient-to-r from-green-600 to-emerald-600 hover:from-green-700 hover:to-emerald-700 disabled:from-zinc-700 disabled:to-zinc-700 disabled:cursor-not-allowed text-white py-3 rounded-xl text-sm font-bold transition-all transform hover:scale-105 active:scale-95 shadow-lg disabled:transform-none flex items-center justify-center gap-2"
            >
              <CreditCard size={18} />
              Solicitar Saque
            </button>
            {saldoDetalhado?.saldoDisponivel < 50 && (
              <p className="text-[10px] text-zinc-400 mt-2 text-center">
                M├¡nimo de R$ 50,00 necess├írio
              </p>
            )}
          </div>
        </div>

        {/* Saldo em Reten├º├úo */}
        <div className="bg-gradient-to-br from-yellow-500/20 to-orange-500/10 rounded-2xl p-6 border border-yellow-500/30 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-yellow-500/10 rounded-full -mr-16 -mt-16"></div>
          <div className="relative">
            <div className="flex items-center justify-between mb-3">
              <p className="text-xs text-yellow-400 font-bold uppercase tracking-wide flex items-center gap-2">
                <Clock size={16} />
                Em Reten├º├úo
              </p>
              <TrendingUp size={18} className="text-yellow-500" />
            </div>
            <p className="text-3xl font-bold text-white mb-2">
              {mostrarSaldo ? `R$ ${(saldoDetalhado?.saldoEmRetencao || 0).toFixed(2)}` : 'R$ ÔÇóÔÇóÔÇóÔÇóÔÇó'}
            </p>
            <div className="bg-yellow-500/10 rounded-lg p-3 mt-4">
              <p className="text-[11px] text-yellow-200 mb-1">­ƒôà Pr├│xima libera├º├úo:</p>
              <p className="text-sm font-bold text-yellow-300">
                {formatarDataCurta(saldoDetalhado?.proximoSaque)}
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Cards de Estat├¡sticas */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <div className="bg-zinc-900/50 rounded-xl p-4 border border-zinc-800">
          <p className="text-[10px] text-zinc-400 font-bold uppercase mb-1">Total L├¡quido</p>
          <p className="text-lg font-bold text-purple-400">
            {mostrarSaldo ? `R$ ${(saldoDetalhado?.totalGanho || 0).toFixed(2)}` : 'R$ ÔÇóÔÇóÔÇóÔÇóÔÇó'}
          </p>
          <p className="text-[9px] text-zinc-500 mt-1">Ap├│s comiss├úo</p>
        </div>

        <div className="bg-zinc-900/50 rounded-xl p-4 border border-zinc-800">
          <p className="text-[10px] text-zinc-400 font-bold uppercase mb-1">Comiss├úo 10%</p>
          <p className="text-lg font-bold text-red-400">
            {mostrarSaldo ? `R$ ${(saldoDetalhado?.comissaoPaga || 0).toFixed(2)}` : 'R$ ÔÇóÔÇóÔÇóÔÇóÔÇó'}
          </p>
          <p className="text-[9px] text-zinc-500 mt-1">Pago ├á plataforma</p>
        </div>

        <div className="bg-zinc-900/50 rounded-xl p-4 border border-zinc-800">
          <p className="text-[10px] text-zinc-400 font-bold uppercase mb-1">M├®dia/Servi├ºo</p>
          <p className="text-lg font-bold text-blue-400">
            {mostrarSaldo ? `R$ ${(saldoDetalhado?.mediaPorServico || 0).toFixed(2)}` : 'R$ ÔÇóÔÇóÔÇóÔÇóÔÇó'}
          </p>
          <p className="text-[9px] text-zinc-500 mt-1">Valor m├®dio</p>
        </div>

        <div className="bg-zinc-900/50 rounded-xl p-4 border border-zinc-800">
          <p className="text-[10px] text-zinc-400 font-bold uppercase mb-1">Servi├ºos/M├¬s</p>
          <p className="text-lg font-bold text-green-400">
            {saldoDetalhado?.servicosMes || 0}
          </p>
          <p className="text-[9px] text-zinc-500 mt-1">Atendimentos</p>
        </div>
      </div>

      {/* Formas de Pagamento */}
      <div className="bg-gradient-to-br from-zinc-900/80 to-zinc-900/40 rounded-2xl p-5 border border-zinc-800">
        <div className="flex items-center gap-2 mb-4">
          <CreditCard size={20} className="text-orange-400" />
          <h3 className="text-lg font-bold text-white">Formas de Pagamento</h3>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-4 gap-2 mb-3">
          <button
            onClick={() => setMetodoPreferido('pix')}
            className={`rounded-lg px-3 py-2 text-sm font-bold border transition ${metodoPreferido === 'pix' ? 'bg-emerald-500/20 border-emerald-500 text-emerald-300' : 'bg-zinc-800 border-zinc-700 text-zinc-300 hover:bg-zinc-700'}`}
          >
            PIX
          </button>
          <button
            onClick={() => setMetodoPreferido('cartao_credito')}
            className={`rounded-lg px-3 py-2 text-sm font-bold border transition ${metodoPreferido === 'cartao_credito' ? 'bg-blue-500/20 border-blue-500 text-blue-300' : 'bg-zinc-800 border-zinc-700 text-zinc-300 hover:bg-zinc-700'}`}
          >
            Cartao Credito
          </button>
          <button
