                  <div className="px-4 pb-4 pt-2 border-t border-zinc-800 bg-zinc-900/50 space-y-2 animate-in slide-in-from-top duration-200">
                    <div className="grid grid-cols-2 gap-3 text-xs">
                      <div>
                        <p className="text-zinc-500 mb-1">Data completa:</p>
                        <p className="text-zinc-300">{formatarDataCompleta(trans.data)}</p>
                      </div>
                      <div>
                        <p className="text-zinc-500 mb-1">ID da transa├º├úo:</p>
                        <p className="text-zinc-300 font-mono">#{trans.id.toString().padStart(6, '0')}</p>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-12">
            <div className="bg-zinc-800/50 rounded-full w-20 h-20 mx-auto flex items-center justify-center mb-4">
              <BarChart3 size={32} className="text-zinc-600" />
            </div>
            <p className="text-zinc-400 text-sm font-medium">
              Nenhuma transa├º├úo {filtro !== 'todos' ? `de ${filtro}` : ''} encontrada
            </p>
            <p className="text-zinc-600 text-xs mt-1">
              Ajuste os filtros para ver outras transa├º├Áes
            </p>
          </div>
        )}
      </div>

      {/* Informa├º├Áes importantes */}
      <div className="bg-gradient-to-r from-blue-500/10 to-purple-500/10 rounded-2xl p-5 border border-blue-500/30">
        <p className="text-sm text-blue-300 font-bold mb-3 flex items-center gap-2">
          Ôä╣´©Å Como funciona o pagamento?
        </p>
        <ul className="space-y-2 text-xs text-zinc-300">
          <li className="flex items-start gap-2">
            <span className="text-green-400 font-bold">Ô£ô</span>
            <span>Ap├│s cada servi├ºo conclu├¡do, o valor ├® creditado automaticamente</span>
          </li>
          <li className="flex items-start gap-2">
            <span className="text-yellow-400 font-bold">ÔÅ▒´©Å</span>
            <span>Valores ficam 7 dias em reten├º├úo para garantia de qualidade</span>
          </li>
          <li className="flex items-start gap-2">
            <span className="text-blue-400 font-bold">­ƒÆ░</span>
            <span>Saques podem ser solicitados com saldo m├¡nimo de R$ 50,00</span>
          </li>
          <li className="flex items-start gap-2">
            <span className="text-purple-400 font-bold">­ƒÅª</span>
            <span>Processamento em at├® 2-3 dias ├║teis na sua conta banc├íria</span>
          </li>
          {userType === 'barbeiro' ? (
            <li className="flex items-start gap-2">
              <span className="text-red-400 font-bold">­ƒÆ│</span>
              <span><strong>Taxa de 10%</strong> sobre cada servi├ºo (descontada automaticamente do total)</span>
            </li>
          ) : (
            <li className="flex items-start gap-2">
              <span className="text-red-400 font-bold">­ƒÆ│</span>
              <span><strong>Assinatura mensal de R$ 49,90</strong> para acesso ├á plataforma</span>
            </li>
          )}
          <li className="flex items-start gap-2">
            <span className="text-green-400 font-bold">­ƒÄë</span>
            <span>Sem taxas ocultas - valores sempre transparentes</span>
          </li>
