      </div>

      {/* Card de Modelo de Cobran├ºa */}
      <div className="bg-gradient-to-br from-orange-500/10 to-red-500/10 rounded-2xl p-5 border border-orange-500/30">
        <div className="flex items-center gap-2 mb-4">
          <div className="bg-orange-500/20 p-2 rounded-lg">
            <DollarSign size={20} className="text-orange-400" />
          </div>
          <h3 className="text-lg font-bold text-white">Modelo de Cobran├ºa BarberMove</h3>
        </div>
        
        <div className="grid sm:grid-cols-2 gap-4">
          <div className="bg-black/30 rounded-xl p-4 border border-zinc-800">
            <p className="text-xs text-purple-400 font-bold uppercase mb-2">­ƒÆê Para Barbeiros</p>
            <div className="flex items-baseline gap-2 mb-2">
              <span className="text-3xl font-bold text-white">10%</span>
