import React, { useState, useEffect } from 'react';
import { Star, MapPin, Phone, Mail, Award, TrendingUp, MessageCircle } from 'lucide-react';

const API_URL = import.meta.env.VITE_API_URL || "http://localhost:8000";

/**
 * Componente de Perfil Aprimorado com Design Melhorado
 * Exibe avalia├º├Áes, estat├¡sticas e informa├º├Áes principais
 */
export default function ProfileCard({ usuarioId, userType, token, isOwnProfile = false }) {
  const [profile, setProfile] = useState(null);
  const [avaliacoes, setAvaliacoes] = useState(null);
  const [loading, setLoading] = useState(true);
  const [erro, setErro] = useState('');
  const [portfolioFotos, setPortfolioFotos] = useState([]);
  const [zoomFoto, setZoomFoto] = useState(null);

  const logErro = (mensagem, detalhe) => {
    if (import.meta.env.DEV) {
      console.error(mensagem, detalhe);
    }
  };

  useEffect(() => {
    carregarPerfil();
  }, [usuarioId]);

  const carregarPerfil = async () => {
    try {
      setLoading(true);
      setErro('');
      
      // Buscar dados do perfil
      const res = await fetch(`${API_URL}/api/v1/usuario/${usuarioId}`, {
        headers: token ? { 'Authorization': `Bearer ${token}` } : {}
      });

      if (!res.ok) {
        throw new Error(`Erro ${res.status}: Usu├írio n├úo encontrado`);
      }

      const data = await res.json();
      setProfile(data);

      // Buscar m├®dia de avalia├º├Áes
      const mediaRes = await fetch(`${API_URL}/api/v1/usuario/${usuarioId}/media_avaliacao`, {
        headers: token ? { 'Authorization': `Bearer ${token}` } : {}
      });

      if (mediaRes.ok) {
        const mediaData = await mediaRes.json();
        setAvaliacoes(mediaData);
      }

      // Buscar fotos do portf├│lio (j├í vem em portfolio_fotos no profile)
      if (data.portfolio_fotos && Array.isArray(data.portfolio_fotos)) {
        setPortfolioFotos(data.portfolio_fotos);
      }
    } catch (err) {
      setErro('Perfil n├úo encontrado. Tente novamente.');
      logErro('Erro ao carregar perfil:', err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-8">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-orange-500 mb-3"></div>
          <div className="text-zinc-400 text-sm">Carregando perfil...</div>
        </div>
      </div>
    );
  }

  if (!profile) {
    return (
      <div className="flex items-center justify-center py-8">
        <div className="text-center">
          <div className="text-red-500 text-sm font-bold mb-2">ÔÜá´©Å Perfil n├úo encontrado</div>
          <div className="text-zinc-400 text-xs">{erro || 'N├úo conseguimos carregar este perfil'}</div>
        </div>
      </div>
    );
  }

  // Calcular m├®dia de avalia├º├Áes
  const mediaAvaliacoes = avaliacoes?.media || 0;
  const totalAvaliacoes = avaliacoes?.total || 0;
  const statusDisponibilidade =
    profile?.presente_em_local && profile?.barbearia_atual_nome
      ? `Dispon├¡vel em ${profile.barbearia_atual_nome}`
      : 'Dispon├¡vel';

  return (
    <div className="space-y-6">
      {/* Foto de Capa */}
      {profile.foto_capa && (
        <div className="relative h-48 rounded-2xl overflow-hidden">
          <img 
            src={profile.foto_capa} 
            alt="Capa do perfil" 
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent"></div>
        </div>
      )}

      {/* Card Principal */}
      <div className={`rounded-2xl border border-zinc-800 overflow-hidden ${
        profile.foto_capa ? '-mt-16' : ''
      }`}>
        <div className="bg-gradient-to-br from-zinc-900 to-black p-6 relative">
          {/* Foto de Perfil */}
          {profile.foto_perfil && (
            <div 
              className="mb-4 cursor-pointer group"
              onClick={() => setZoomFoto(profile.foto_perfil)}
            >
              <img 
                src={profile.foto_perfil} 
                alt={profile.nome} 
                className="w-24 h-24 rounded-full border-4 border-zinc-800 object-cover group-hover:opacity-80 transition-opacity"
              />
              <p className="text-xs text-zinc-500 mt-1">Toque para ampliar</p>
            </div>
          )}

          {/* Informa├º├Áes Principais */}
          <div className="flex justify-between items-start mb-4">
            <div className="flex-1">
              <h1 className="text-3xl font-bold text-white mb-1">{profile.nome}</h1>
              <p className="text-zinc-400 text-sm capitalize">{userType}</p>
            </div>

            {/* Badge de Status */}
            {profile.disponivel && (
              <div className="px-4 py-2 bg-green-500/20 border border-green-500/50 rounded-full">
                <p className="text-xs text-green-400 font-bold flex items-center gap-1">
                  ÔùÅ {statusDisponibilidade}
                </p>
              </div>
            )}
          </div>

          {/* Rating Stars */}
          <div className="flex items-center gap-3 mb-6 pb-6 border-b border-zinc-800">
            <div className="flex items-center gap-1">
              {[...Array(5)].map((_, i) => (
                <Star
                  key={i}
                  size={20}
                  className={i < Math.round(mediaAvaliacoes) ? 'text-yellow-400 fill-yellow-400' : 'text-zinc-700'}
                />
              ))}
            </div>
            <div>
              <p className="text-sm font-bold text-white">
                {mediaAvaliacoes.toFixed(1)} de 5 estrelas
              </p>
              <p className="text-xs text-zinc-400">
                ({totalAvaliacoes} {totalAvaliacoes === 1 ? 'avalia├º├úo' : 'avalia├º├Áes'})
              </p>
            </div>
          </div>

          {/* Contato e Localiza├º├úo */}
          <div className="space-y-3">
            {profile.endereco && (
              <div className="flex items-start gap-3">
                <MapPin size={18} className="text-orange-400 shrink-0 mt-1" />
                <div>
                  <p className="text-xs text-zinc-400">Localiza├º├úo</p>
                  <p className="text-sm text-white">{profile.endereco}</p>
                </div>
              </div>
            )}

            {profile.telefone && (
              <div className="flex items-start gap-3">
                <Phone size={18} className="text-green-400 shrink-0 mt-1" />
                <div>
                  <p className="text-xs text-zinc-400">Telefone</p>
                  <p className="text-sm text-white">{profile.telefone}</p>
                </div>
              </div>
            )}

            {profile.email && (
              <div className="flex items-start gap-3">
                <Mail size={18} className="text-blue-400 shrink-0 mt-1" />
                <div>
                  <p className="text-xs text-zinc-400">Email</p>
                  <p className="text-sm text-white break-all">{profile.email}</p>
                </div>
              </div>
            )}
          </div>

          {/* Bot\u00e3o WhatsApp */}
          {profile.telefone && userType === 'barbeiro' && (
            <div className="mt-6 pt-6 border-t border-zinc-800">
              <a
                href={`https://wa.me/55${profile.telefone.replace(/\D/g, '')}`}
                target="_blank"
                rel="noopener noreferrer"
                className="w-full bg-green-600 text-white px-4 py-3 rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-green-700 active:scale-95 transition-all"
              >
                <MessageCircle size={20} />
                Entrar em Contato via WhatsApp
              </a>
            </div>
          )}
        </div>
      </div>

      {/* Estat├¡sticas */}
      {(profile.total_agendamentos || profile.tempo_experiencia) && (
        <div className="grid grid-cols-2 gap-4">
          {profile.total_agendamentos !== undefined && (
            <div className="bg-zinc-900 border border-zinc-800 rounded-lg p-4">
              <div className="flex items-center gap-2 mb-2">
                <TrendingUp size={18} className="text-blue-500" />
                <p className="text-xs text-zinc-400 font-bold">Total Atendimentos</p>
              </div>
              <p className="text-2xl font-bold text-white">{profile.total_agendamentos || 0}</p>
            </div>
          )}

          {profile.tempo_experiencia && (
            <div className="bg-zinc-900 border border-zinc-800 rounded-lg p-4">
              <div className="flex items-center gap-2 mb-2">
                <Award size={18} className="text-purple-500" />
                <p className="text-xs text-zinc-400 font-bold">Experi├¬ncia</p>
              </div>
              <p className="text-2xl font-bold text-white">{profile.tempo_experiencia}</p>
            </div>
          )}
        </div>
      )}

      {/* Portf├│lio (se houver fotos) */}
      {(profile.portfolio_fotos && profile.portfolio_fotos.length > 0) || portfolioFotos.length > 0 ? (
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
          <h3 className="text-lg font-bold text-white mb-4">Portf├│lio</h3>
          <div className="grid grid-cols-3 gap-3">
            {(profile.portfolio_fotos && profile.portfolio_fotos.length > 0 ? profile.portfolio_fotos : portfolioFotos).map((foto, idx) => (
              <div 
                key={idx} 
                className="aspect-square rounded-lg overflow-hidden border border-zinc-800 cursor-pointer group"
                onClick={() => setZoomFoto(foto)}
              >
                <img 
                  src={foto} 
                  alt={`Portf├│lio ${idx + 1}`} 
                  className="w-full h-full object-cover group-hover:scale-105 transition-transform"
                />
              </div>
            ))}
          </div>
        </div>
      ) : null}

      {/* ├Ültimas Avalia├º├Áes */}
      {avaliacoes?.ultimas && avaliacoes.ultimas.length > 0 && (
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
          <h3 className="text-lg font-bold text-white mb-4">├Ültimas Avalia├º├Áes</h3>
          <div className="space-y-3">
            {avaliacoes.ultimas.map((aval, idx) => (
              <div key={idx} className="bg-black/50 p-4 rounded-lg border border-zinc-800/50">
                <div className="flex justify-between items-start mb-2">
                  <div>
                    <p className="font-bold text-white">{aval.avaliador_nome || 'Usu├írio'}</p>
                    <p className="text-xs text-zinc-400">
                      {new Date(aval.data).toLocaleDateString('pt-BR')}
                    </p>
                  </div>
                  <div className="flex gap-1">
                    {[...Array(5)].map((_, i) => (
                      <Star
                        key={i}
                        size={16}
                        className={i < aval.nota ? 'text-yellow-400 fill-yellow-400' : 'text-zinc-700'}
                      />
                    ))}
                  </div>
                </div>
                {aval.comentario && (
                  <p className="text-sm text-zinc-300">{aval.comentario}</p>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Modal de Zoom Seguro */}
      {zoomFoto && (
        <div 
          className="fixed inset-0 bg-black z-50 flex items-center justify-center p-2"
          onClick={() => setZoomFoto(null)}
        >
          <div onClick={(e) => e.stopPropagation()} className="relative">
            <button
              onClick={() => setZoomFoto(null)}
              className="absolute -top-10 right-0 bg-red-600 text-white px-3 py-1 rounded text-xs font-bold hover:bg-red-700"
            >
              Ô£ò Fechar
            </button>
            <img 
              src={zoomFoto}
              alt="Zoom"
              className="max-w-[90vw] max-h-[85vh] object-contain rounded-lg"
            />
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * SeletorCategoria.jsx
 * 
 * Componente para selecionar uma categoria de servi├ºo.
 * 
 * Oferece 8 categorias fixas com labels amig├íveis:
 * - CORTE ÔåÆ "Corte de Cabelo"
 * - BARBA ÔåÆ "Barba e Bigode"
 * - SOBRANCELHA ÔåÆ "Design de Sobrancelha"
 * - QUIMICA ÔåÆ "Qu├¡mica/Alisamento"
 * - INFANTIL ÔåÆ "Corte Infantil"
 * - TRATAMENTO ÔåÆ "Tratamento Capilar"
 * - COMBO ÔåÆ "Pacote Combo"
 * - OUTROS ÔåÆ "Outros Servi├ºos"
 * 
 * O campo nome ├® livre (criatividade do dono).
 * A categoria ├® padr├úo (para organiza├º├úo e relat├│rios).
 */

export const CATEGORIAS_SERVICOS = [
  { valor: "corte", label: "Corte de Cabelo" },
  { valor: "barba", label: "Barba e Bigode" },
  { valor: "sobrancelha", label: "Design de Sobrancelha" },
  { valor: "quimica", label: "Qu├¡mica/Alisamento" },
  { valor: "infantil", label: "Corte Infantil" },
  { valor: "tratamento", label: "Tratamento Capilar" },
  { valor: "combo", label: "Pacote Combo" },
  { valor: "outros", label: "Outros Servi├ºos" }
];

export default function SeletorCategoria({ 
  valor = "", 
  onChange = () => {},
  label = "Categoria do Servi├ºo",
  obrigatorio = true,
  desabilitado = false,
  className = ""
}) {
  return (
    <div className={`selector-categoria-wrapper ${className}`}>
      <label htmlFor="categoria-select">
        {label}
        {obrigatorio && <span className="required">*</span>}
      </label>
      
      <select
        id="categoria-select"
        value={valor}
        onChange={(e) => onChange(e.target.value)}
        disabled={desabilitado}
        className={`categoria-select ${valor ? "selected" : "placeholder"}`}
        required={obrigatorio}
      >
        <option value="">Escolha uma categoria...</option>
        {CATEGORIAS_SERVICOS.map((cat) => (
          <option key={cat.valor} value={cat.valor}>
            {cat.label}
          </option>
        ))}
      </select>

      <style jsx>{`
        .selector-categoria-wrapper {
          display: flex;
          flex-direction: column;
          gap: 0.5rem;
        }

        label {
          font-size: 0.875rem;
          font-weight: 600;
          color: #333;
          text-transform: uppercase;
          letter-spacing: 0.5px;
        }

        .required {
          color: #e74c3c;
          margin-left: 0.25rem;
        }

        .categoria-select {
          padding: 0.75rem;
          border: 2px solid #e0e0e0;
          border-radius: 6px;
          font-size: 1rem;
          background-color: white;
          cursor: pointer;
          transition: all 0.2s ease;
        }

        .categoria-select:hover:not(:disabled) {
          border-color: #9c27b0;
          box-shadow: 0 2px 8px rgba(156, 39, 176, 0.15);
        }

        .categoria-select:focus {
          outline: none;
          border-color: #9c27b0;
          box-shadow: 0 0 0 3px rgba(156, 39, 176, 0.1);
        }

        .categoria-select.selected {
          color: #333;
          font-weight: 500;
        }

        .categoria-select.placeholder {
          color: #999;
        }

        .categoria-select:disabled {
          background-color: #f5f5f5;
          color: #999;
          cursor: not-allowed;
          opacity: 0.6;
        }

        .categoria-select option {
          padding: 0.5rem;
          color: #333;
        }
      `}</style>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Store, LogOut, CheckCircle, AlertCircle, User, CreditCard, Calendar, Search, Star, ThumbsUp, TrendingUp } from 'lucide-react';
import PaymentSection from './PaymentSection';
import AbaPadronizadaAvaliacoes from './AbaPadronizadaAvaliacoes';
import TelaPerfilUsuario from './TelaPerfilUsuario';
import LiberarCadeirasComponent from './LiberarCadeirasComponent';
import TelaMensalidadeAssinatura from './TelaMensalidadeAssinatura';

export default function ShopDashboard({ token, logout, notify, API_URL }) {
    const [services, setServices] = useState([{id: 1, nome: "Corte Simples", valor: 30}]);
    const [newService, setNewService] = useState({nome: '', valor: ''});
    const [user, setUser] = useState(null);
    const [userData, setUserData] = useState(null);
    const [tab, setTab] = useState('barbeiros');
    const [agendamentos, setAgendamentos] = useState([]);
    const [freelancersPresentes, setFreelancersPresentes] = useState([]);
    const [freelancersDisponiveis, setFreelancersDisponiveis] = useState([]);
    const [freelancersPendentesAprovacao, setFreelancersPendentesAprovacao] = useState([]);
    const [ultimaAtualizacaoFreelancers, setUltimaAtualizacaoFreelancers] = useState(null);
    const [wsConectado, setWsConectado] = useState(false);
    const [loading, setLoading] = useState(false);
    const [barbeariaId, setBarbeariaId] = useState(null);

    useEffect(() => {
        fetch(`${API_URL}/api/v1/documentos/status`, {
            headers: {'Authorization': `Bearer ${token}`}
        })
        .then(r => r.json())
        .then(data => {
            setUser(data);
            if (!userData) setUserData(data);
        })
        .catch(() => {});

        // Carregar barbearia do usu├írio autenticado
        fetch(`${API_URL}/api/v1/barbearia/minha`, {
            headers: {'Authorization': `Bearer ${token}`}
        })
        .then(r => r.ok ? r.json() : null)
        .then(data => {
            if (data && data.id) {
                setBarbeariaId(data.id);
                setUserData(prev => ({ ...(prev || {}), id: data.usuario_id || prev?.id }));
            }
        })
        .catch(() => {});
    }, [API_URL, token]);

    // Carregar agendamentos da barbearia
    useEffect(() => {
        if (!barbeariaId) return;
        
        const carregarAgendamentos = async () => {
            try {
                const res = await fetch(`${API_URL}/api/v1/barbearias/${barbeariaId}/agendamentos`, {
                    headers: {'Authorization': `Bearer ${token}`}
                });
                if (res.ok) {
                    const data = await res.json();
                    setAgendamentos(Array.isArray(data) ? data : []);
                }
            } catch (err) {
                console.error('Erro ao carregar agendamentos:', err);
            }
        };
        
        carregarAgendamentos();
        const interval = setInterval(carregarAgendamentos, 10000);
        return () => clearInterval(interval);
    }, [barbeariaId, API_URL, token]);

    // Alterar status do freelancer (controle duplo)
    const alterarStatusFreelancer = async (freelancerId, novoStatus, barbeariaIdAlvo = null) => {
        try {
            const res = await fetch(`${API_URL}/api/v1/freelancer/${freelancerId}/alterar-status`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    status: novoStatus,
                    barbearia_id: barbeariaIdAlvo || barbeariaId
                })
            });

            if (res.ok) {
                const data = await res.json();
                notify(`Status do freelancer alterado para ${novoStatus.toUpperCase()}`, 'success');
                // Recarregar dados
                if (barbeariaId) {
                    carregarFreelancersPresentes();
                }
            } else {
                const error = await res.json().catch(() => ({}));
                notify(error.detail || 'Erro ao alterar status', 'error');
            }
        } catch (err) {
            notify('Erro ao conectar com servidor', 'error');
        }
    };

    // Bloquear freelancer
    const bloquearFreelancer = async (freelancerId, motivo) => {
        if (!barbeariaId) {
            notify('Barbearia n├úo identificada', 'error');
            return;
        }

        try {
            const res = await fetch(`${API_URL}/api/v1/barbearia/${barbeariaId}/bloquear-freelancer`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    freelancer_id: freelancerId,
                    motivo: motivo
                })
            });

            if (res.ok) {
                notify('Freelancer bloqueado com sucesso', 'success');
                carregarFreelancersPresentes();
            } else {
                const error = await res.json().catch(() => ({}));
                notify(error.detail || 'Erro ao bloquear freelancer', 'error');
            }
        } catch (err) {
            notify('Erro ao conectar com servidor', 'error');
        }
    };

    // Avaliar freelancer
    const avaliarFreelancer = async (freelancerId, chamadoId, nota, comentario) => {
        if (!barbeariaId) {
            notify('Barbearia n├úo identificada', 'error');
            return;
        }

        try {
            const res = await fetch(`${API_URL}/api/v1/barbearia/${barbeariaId}/avaliar-freelancer`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    freelancer_id: freelancerId,
                    chamado_id: chamadoId,
                    nota: nota,
                    comentario: comentario
                })
            });

            if (res.ok) {
                notify('Avalia├º├úo enviada com sucesso!', 'success');
            } else {
                const error = await res.json().catch(() => ({}));
                notify(error.detail || 'Erro ao enviar avalia├º├úo', 'error');
            }
        } catch (err) {
            notify('Erro ao conectar com servidor', 'error');
        }
    };

    // Carregar freelancers presentes
    const carregarFreelancersPresentes = async () => {
        if (!barbeariaId) return;
        
        try {
            const res = await fetch(`${API_URL}/api/v1/barbearia/${barbeariaId}/barbeiros-presentes`, {
                headers: {'Authorization': `Bearer ${token}`}
            });
            if (res.ok) {
                const data = await res.json();
                setFreelancersPresentes(Array.isArray(data) ? data : []);
                setUltimaAtualizacaoFreelancers(new Date());
            }
        } catch (err) {
            console.error('Erro ao carregar freelancers:', err);
        }
    };

    const carregarFreelancersDisponiveis = async () => {
        try {
            const res = await fetch(`${API_URL}/api/v1/freelancer/todos`, {
                headers: {'Authorization': `Bearer ${token}`}
            });
            if (!res.ok) {
                setFreelancersDisponiveis([]);
                return;
            }

            const data = await res.json();
            const lista = Array.isArray(data) ? data : [];

            const pendentes = lista.filter((f) => !f?.perfil_aprovado);
            setFreelancersPendentesAprovacao(pendentes);

            const disponiveis = lista.filter((f) => {
                if (!f?.perfil_aprovado) return false;
                if (!f?.disponivel || f?.offline) return false;
                if (f?.presente_em_local && f?.barbearia_atual_id && f.barbearia_atual_id !== barbeariaId) return false;
                return true;
            });

            setFreelancersDisponiveis(disponiveis);
            setUltimaAtualizacaoFreelancers(new Date());
        } catch (err) {
            console.error('Erro ao carregar freelancers dispon├¡veis:', err);
            setFreelancersDisponiveis([]);
            setFreelancersPendentesAprovacao([]);
        }
    };

    useEffect(() => {
        if (!barbeariaId || tab !== 'barbeiros') return;

        // Sincroniza├º├úo inicial sempre ocorre.
        carregarFreelancersPresentes();
        carregarFreelancersDisponiveis();

        // Se o WebSocket estiver conectado, n├úo precisamos de polling.
        if (wsConectado) return;

        const interval = setInterval(() => {
            carregarFreelancersPresentes();
            carregarFreelancersDisponiveis();
        }, 5000);
        return () => clearInterval(interval);
    }, [barbeariaId, tab, wsConectado, API_URL, token]);

    useEffect(() => {
        if (!barbeariaId || tab !== 'barbeiros') return;

        const wsBase = API_URL.replace(/^http/, 'ws');
        const ws = new WebSocket(`${wsBase}/ws/notificacoes`);

        ws.onopen = () => {
            setWsConectado(true);
        };

        ws.onmessage = (event) => {
            try {
                const data = JSON.parse(event.data);
                if (data?.type !== 'freelancer_status_changed') return;

                const eventoBarbeariaId = data?.barbearia_id;
                if (eventoBarbeariaId && Number(eventoBarbeariaId) !== Number(barbeariaId)) {
                    return;
                }

                carregarFreelancersPresentes();
                carregarFreelancersDisponiveis();
            } catch {
                // Ignora mensagens n├úo JSON como ping/pong
            }
        };

        ws.onclose = () => {
            setWsConectado(false);
        };

        ws.onerror = () => {
            setWsConectado(false);
        };

        return () => {
            setWsConectado(false);
            ws.close();
        };
    }, [API_URL, barbeariaId, tab]);

    const addService = (e) => {
        e.preventDefault();
        if (!newService.nome || !newService.valor) {
            notify("Preencha nome e valor", "error");
            return;
        }
        setServices([...services, {id: Date.now(), nome: newService.nome, valor: parseFloat(newService.valor)}]);
        setNewService({nome: '', valor: ''});
        notify("Servi├ºo adicionado!", "success");
    };

    return (
        <div className="bg-black h-full w-full max-w-full overflow-hidden flex flex-col text-white font-sans">
            <div className="p-2 sm:p-4 flex justify-between items-center border-b border-zinc-800 bg-black/80 backdrop-blur-md z-20 flex-shrink-0">
                <div className="flex items-center gap-2">
                    <h1 className="text-base sm:text-xl font-bold flex items-center gap-2">
                        <Store size={18} className="text-orange-500"/> Loja
                    </h1>
                    {user?.documento_verificado && (
                        <CheckCircle size={14} className="text-blue-500 fill-blue-500" />
                    )}
                </div>
                <button onClick={logout} className="text-zinc-500 hover:text-white"><LogOut size={18}/></button>
            </div>

            <div className="flex-1 overflow-y-auto pb-16">
                
                {tab === 'barbeiros' && (
                    <div className="p-2 sm:p-4 space-y-3 pb-20">
                        {user && !user.documento_verificado && (
                            <div className="bg-yellow-600/10 border border-yellow-600/30 p-2 rounded-lg flex items-center gap-2">
                                <AlertCircle size={14} className="text-yellow-500"/>
                                <span className="text-yellow-400 text-xs">Verifica├º├úo pendente</span>
                            </div>
                        )}
                        
                        <h2 className="text-sm font-bold text-zinc-400 uppercase">Freelancers Presentes</h2>
                        <div className="bg-green-900/20 border border-green-700 rounded-lg p-2.5 flex items-center justify-between">
                            <div className="flex items-center gap-2">
                                <span className="h-2.5 w-2.5 rounded-full bg-green-400 animate-pulse"></span>
                                <span className="text-xs font-bold text-green-300">EM TEMPO REAL</span>
                            </div>
                            <span className="text-[11px] text-zinc-300">
                                {ultimaAtualizacaoFreelancers
                                    ? `Atualizado ├ás ${ultimaAtualizacaoFreelancers.toLocaleTimeString('pt-BR')}`
                                    : 'Sincronizando...'}
                            </span>
                        </div>
                        <p className="text-[11px] text-zinc-500">
                            {wsConectado ? 'Canal ao vivo: WebSocket conectado' : 'Canal ao vivo: reconectando (fallback por polling ativo)'}
                        </p>
                        <div className="bg-zinc-900/50 border border-zinc-800 rounded-lg p-3 space-y-2">
                            <div className="flex items-center justify-between">
                                <h3 className="text-xs font-bold text-zinc-400 uppercase">Dispon├¡veis para sua Barbearia</h3>
                                <span className="text-[11px] text-green-400 font-bold">{freelancersDisponiveis.length}</span>
                            </div>
                            {freelancersDisponiveis.length === 0 ? (
                                <p className="text-zinc-600 text-xs">Nenhum barbeiro dispon├¡vel agora.</p>
                            ) : (
                                <div className="space-y-2">
                                    {freelancersDisponiveis.slice(0, 6).map((f) => (
                                        <div key={f.usuario_id} className="bg-black/40 border border-zinc-700 rounded p-2">
                                            <p className="text-sm font-bold text-white">{f.nome}</p>
                                            <p className="text-[11px] text-zinc-400">{f.presente_em_local ? 'Dispon├¡vel no local' : 'Dispon├¡vel na regi├úo'}</p>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        <div className="bg-zinc-900/50 border border-zinc-800 rounded-lg p-3 space-y-2">
                            <div className="flex items-center justify-between">
                                <h3 className="text-xs font-bold text-zinc-400 uppercase">Aguardando Aprova├º├úo</h3>
                                <span className="text-[11px] text-yellow-400 font-bold">{freelancersPendentesAprovacao.length}</span>
                            </div>
                            {freelancersPendentesAprovacao.length === 0 ? (
                                <p className="text-zinc-600 text-xs">Nenhum barbeiro pendente no momento.</p>
                            ) : (
                                <div className="space-y-2">
                                    {freelancersPendentesAprovacao.slice(0, 6).map((f) => (
                                        <div key={f.usuario_id} className="bg-black/40 border border-zinc-700 rounded p-2">
                                            <p className="text-sm font-bold text-white">{f.nome}</p>
                                            <p className="text-[11px] text-zinc-400">Perfil em an├ílise pelo admin</p>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                        
                        <button
                            onClick={() => {
                                carregarFreelancersPresentes();
                                carregarFreelancersDisponiveis();
                            }}
                            className="w-full py-2 bg-zinc-800 hover:bg-zinc-700 rounded text-xs font-bold"
                        >
                            ­ƒöä Atualizar Lista
                        </button>

                        {freelancersPresentes.length === 0 ? (
                            <p className="text-zinc-600 text-center py-8 text-xs">Nenhum freelancer presente no momento</p>
                        ) : (
                            <div className="space-y-2">
                                {freelancersPresentes.map(freelancer => (
                                    <div key={freelancer.id} className="bg-zinc-900/50 border border-zinc-800 p-3 rounded-lg space-y-2">
                                        <div className="flex justify-between items-start">
                                            <div>
                                                <p className="font-bold text-sm">{freelancer.nome}</p>
                                                <p className="text-xs text-zinc-400">{freelancer.email}</p>
                                            </div>
                                            <div className="h-2 w-2 bg-green-500 rounded-full animate-pulse"></div>
                                        </div>

                                        {/* ­ƒÄø´©Å CONTROLE DE STATUS (Controle Duplo) */}
                                        <div className="space-y-2 pt-2 border-t border-zinc-700">
                                            <p className="text-xs text-zinc-400 font-bold">Alterar Status:</p>
                                            <div className="grid grid-cols-3 gap-2">
                                                <button
                                                    onClick={() => alterarStatusFreelancer(freelancer.id, 'offline')}
                                                    className="py-2 px-2 bg-red-600/20 hover:bg-red-600/30 border border-red-600/50 text-red-400 rounded text-xs font-bold"
                                                >
                                                    OFFLINE
                                                </button>
                                                <button
                                                    onClick={() => alterarStatusFreelancer(freelancer.id, 'online')}
                                                    className="py-2 px-2 bg-green-600/20 hover:bg-green-600/30 border border-green-600/50 text-green-400 rounded text-xs font-bold"
                                                >
                                                    ONLINE
                                                </button>
                                                <button
                                                    onClick={() => alterarStatusFreelancer(freelancer.id, 'presente', barbeariaId)}
                                                    className="py-2 px-2 bg-blue-600/20 hover:bg-blue-600/30 border border-blue-600/50 text-blue-400 rounded text-xs font-bold"
                                                >
                                                    PRESENTE
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}

                        <h2 className="text-sm font-bold text-zinc-400 uppercase mt-6">Meus Servi├ºos</h2>
                        <div className="bg-zinc-900/50 p-3 rounded-lg border border-zinc-800/50">
                            <form onSubmit={addService} className="space-y-2 mb-3">
                                <input
                                    className="w-full bg-black/50 text-white text-xs p-2 rounded border border-zinc-800 focus:border-orange-500 outline-none"
                                    placeholder="Nome do servi├ºo"
                                    value={newService.nome}
                                    onChange={e => setNewService({...newService, nome: e.target.value})}
                                    required
                                />
                                <div className="flex gap-2">
                                    <input
                                        className="flex-1 bg-black/50 text-white text-xs p-2 rounded border border-zinc-800 focus:border-orange-500 outline-none"
                                        type="number"
                                        placeholder="Valor R$"
                                        value={newService.valor}
                                        onChange={e => setNewService({...newService, valor: e.target.value})}
                                        required
                                    />
                                    <button className="bg-orange-600 hover:bg-orange-700 text-white text-xs px-3 rounded font-bold transition">Adicionar</button>
                                </div>
                            </form>
                            
                            <div className="space-y-2">
                                {services.map(s => (
                                    <div key={s.id} className="flex justify-between items-center bg-black/40 p-2 rounded text-xs">
                                        <span>{s.nome}</span>
