                                                </div>
                                                <button
                                                    onClick={() => {
                                                        if (confirm(`Bloquear ${ag.barbeiro_nome} de trabalhar na sua barbearia?`)) {
                                                            const motivo = prompt('Motivo do bloqueio:');
                                                            if (motivo) {
