                                                        }
                                                    }}
                                                    className="w-full py-2 bg-red-600/20 hover:bg-red-600/30 border border-red-600/50 text-red-400 rounded text-xs font-bold"
                                                >
                                                    ­ƒÜ½ Bloquear Freelancer
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}

                {tab === 'aprovar' && (
                    <div className="p-2 sm:p-4">
                        <h2 className="text-sm font-bold text-zinc-400 uppercase mb-4">Aprova├º├Áes</h2>
                        <p className="text-zinc-600 text-center py-12 text-xs">Nenhuma aprova├º├úo</p>
                    </div>
                )}

                {tab === 'avaliar' && (
                    <div className="p-2 sm:p-4 pb-20">
                        {userData ? (
                            <AbaPadronizadaAvaliacoes
                                usuarioId={userData.id}
                                tipoUsuario="barbearia"
                                nomeUsuario={userData.nome}
                                API_URL={API_URL}
                                token={token}
                                notify={notify}
