                )}

                {tab === 'perfil' && (
                    <TelaPerfilUsuario userType="barbearia" token={token} onLogout={logout} onNotify={notify} />
                )}

                {tab === 'assinatura' && barbeariaId && (
                    <div className="p-2 sm:p-4 pb-24">
                        <TelaMensalidadeAssinatura
                            token={token}
                            barbeariaId={barbeariaId}
                            API_URL={API_URL}
